    if( IO_PRO.SEN.SENTOP.SENTOPCTL1.SENTOPCTL13.bit.LDIVMCH   != sentop_ctrl->ldiv_multi_ch_input_ctrl ) Ddim_Print(( "Im_PRO_SENTOP_Ctrl() %s result:LDIVMCH    (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.SENTOPCTL1.SENTOPCTL13.bit.LDIVMCH   , sentop_ctrl->ldiv_multi_ch_input_ctrl  ));
    if( IO_PRO.SEN.SENTOP.SENTOPCTL2.SENTOPCTL2_1.bit.ORG00    != sentop_ctrl->first_pixel[0][0]        ) Ddim_Print(( "Im_PRO_SENTOP_Ctrl() %s result:ORG00      (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.SENTOPCTL2.SENTOPCTL2_1.bit.ORG00    , sentop_ctrl->first_pixel[0][0]         ));
    if( IO_PRO.SEN.SENTOP.SENTOPCTL2.SENTOPCTL2_1.bit.ORG01    != sentop_ctrl->first_pixel[0][1]        ) Ddim_Print(( "Im_PRO_SENTOP_Ctrl() %s result:ORG01      (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.SENTOPCTL2.SENTOPCTL2_1.bit.ORG01    , sentop_ctrl->first_pixel[0][1]         ));
    if( IO_PRO.SEN.SENTOP.SENTOPCTL2.SENTOPCTL2_1.bit.ORG10    != sentop_ctrl->first_pixel[1][0]        ) Ddim_Print(( "Im_PRO_SENTOP_Ctrl() %s result:ORG10      (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.SENTOPCTL2.SENTOPCTL2_1.bit.ORG10    , sentop_ctrl->first_pixel[1][0]         ));
    if( IO_PRO.SEN.SENTOP.SENTOPCTL2.SENTOPCTL2_1.bit.ORG11    != sentop_ctrl->first_pixel[1][1]        ) Ddim_Print(( "Im_PRO_SENTOP_Ctrl() %s result:ORG11      (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.SENTOPCTL2.SENTOPCTL2_1.bit.ORG11    , sentop_ctrl->first_pixel[1][1]         ));
    if( IO_PRO.SEN.SENTOP.SENTOPCTL2.SENTOPCTL2_2.bit.ORG20    != sentop_ctrl->first_pixel[2][0]        ) Ddim_Print(( "Im_PRO_SENTOP_Ctrl() %s result:ORG20      (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.SENTOPCTL2.SENTOPCTL2_2.bit.ORG20    , sentop_ctrl->first_pixel[2][0]         ));
    if( IO_PRO.SEN.SENTOP.SENTOPCTL2.SENTOPCTL2_2.bit.ORG21    != sentop_ctrl->first_pixel[2][1]        ) Ddim_Print(( "Im_PRO_SENTOP_Ctrl() %s result:ORG21      (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.SENTOPCTL2.SENTOPCTL2_2.bit.ORG21    , sentop_ctrl->first_pixel[2][1]         ));
    if( IO_PRO.SEN.SENTOP.SENTOPCTL2.SENTOPCTL2_2.bit.ORG30    != sentop_ctrl->first_pixel[3][0]        ) Ddim_Print(( "Im_PRO_SENTOP_Ctrl() %s result:ORG30      (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.SENTOPCTL2.SENTOPCTL2_2.bit.ORG30    , sentop_ctrl->first_pixel[3][0]         ));
    if( IO_PRO.SEN.SENTOP.SENTOPCTL2.SENTOPCTL2_2.bit.ORG31    != sentop_ctrl->first_pixel[3][1]        ) Ddim_Print(( "Im_PRO_SENTOP_Ctrl() %s result:ORG31      (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.SENTOPCTL2.SENTOPCTL2_2.bit.ORG31    , sentop_ctrl->first_pixel[3][1]         ));
