VOID CT_Im_PRO_1_5_Print( const char* string, T_IM_PRO_SENTOP_BS_CTRL* sentop_ctrl )
{
    if(IO_PRO.SEN.SENTOP.BSCTL.BSCTL1.bit.BSAMNT0!= sentop_ctrl->shift_value[0]     ) Ddim_Print(( "Im_PRO_SENTOP_BS_Ctrl() %s result:BSAMNT0 (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.BSCTL.BSCTL1.bit.BSAMNT0, sentop_ctrl->shift_value[0]     ));
    if(IO_PRO.SEN.SENTOP.BSCTL.BSCTL1.bit.BSAMNT1!= sentop_ctrl->shift_value[1]     ) Ddim_Print(( "Im_PRO_SENTOP_BS_Ctrl() %s result:BSAMNT1 (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.BSCTL.BSCTL1.bit.BSAMNT1, sentop_ctrl->shift_value[1]     ));
    if(IO_PRO.SEN.SENTOP.BSCTL.BSCTL1.bit.BSAMNT2!= sentop_ctrl->shift_value[2]     ) Ddim_Print(( "Im_PRO_SENTOP_BS_Ctrl() %s result:BSAMNT2 (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.BSCTL.BSCTL1.bit.BSAMNT2, sentop_ctrl->shift_value[2]     ));
    if(IO_PRO.SEN.SENTOP.BSCTL.BSCTL1.bit.BSAMNT3!= sentop_ctrl->shift_value[3]     ) Ddim_Print(( "Im_PRO_SENTOP_BS_Ctrl() %s result:BSAMNT3 (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.BSCTL.BSCTL1.bit.BSAMNT3, sentop_ctrl->shift_value[3]     ));
    if(IO_PRO.SEN.SENTOP.BSCTL.BSCTL1.bit.BSLMD0 != sentop_ctrl->sat_compensation[0]) Ddim_Print(( "Im_PRO_SENTOP_BS_Ctrl() %s result:BSLMD0  (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.BSCTL.BSCTL1.bit.BSLMD0 , sentop_ctrl->sat_compensation[0]    ));
    if(IO_PRO.SEN.SENTOP.BSCTL.BSCTL1.bit.BSLMD1 != sentop_ctrl->sat_compensation[1]) Ddim_Print(( "Im_PRO_SENTOP_BS_Ctrl() %s result:BSLMD1  (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.BSCTL.BSCTL1.bit.BSLMD1 , sentop_ctrl->sat_compensation[1]    ));
    if(IO_PRO.SEN.SENTOP.BSCTL.BSCTL1.bit.BSLMD2 != sentop_ctrl->sat_compensation[2]) Ddim_Print(( "Im_PRO_SENTOP_BS_Ctrl() %s result:BSLMD2  (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.BSCTL.BSCTL1.bit.BSLMD2 , sentop_ctrl->sat_compensation[2]    ));
    if(IO_PRO.SEN.SENTOP.BSCTL.BSCTL1.bit.BSLMD3 != sentop_ctrl->sat_compensation[3]) Ddim_Print(( "Im_PRO_SENTOP_BS_Ctrl() %s result:BSLMD3  (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.BSCTL.BSCTL1.bit.BSLMD3 , sentop_ctrl->sat_compensation[3]    ));
    if(IO_PRO.SEN.SENTOP.BSCTL.BSCTL2.bit.BSLR0  != sentop_ctrl->shift_dir[0]       ) Ddim_Print(( "Im_PRO_SENTOP_BS_Ctrl() %s result:BSLR0   (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.BSCTL.BSCTL2.bit.BSLR0  , sentop_ctrl->shift_dir[0]       ));
    if(IO_PRO.SEN.SENTOP.BSCTL.BSCTL2.bit.BSLR1  != sentop_ctrl->shift_dir[1]       ) Ddim_Print(( "Im_PRO_SENTOP_BS_Ctrl() %s result:BSLR1   (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.BSCTL.BSCTL2.bit.BSLR1  , sentop_ctrl->shift_dir[1]       ));
    if(IO_PRO.SEN.SENTOP.BSCTL.BSCTL2.bit.BSLR2  != sentop_ctrl->shift_dir[2]       ) Ddim_Print(( "Im_PRO_SENTOP_BS_Ctrl() %s result:BSLR2   (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.BSCTL.BSCTL2.bit.BSLR2  , sentop_ctrl->shift_dir[2]       ));
    if(IO_PRO.SEN.SENTOP.BSCTL.BSCTL2.bit.BSLR3  != sentop_ctrl->shift_dir[3]       ) Ddim_Print(( "Im_PRO_SENTOP_BS_Ctrl() %s result:BSLR3   (%d) in(%d)\n", string, IO_PRO.SEN.SENTOP.BSCTL.BSCTL2.bit.BSLR3  , sentop_ctrl->shift_dir[3]       ));
}

