VOID CT_Im_PRO_1_9( const UINT32 idx )
{
    INT32 ercd;
    T_IM_PRO_SENTOP_SLVS_CTRL slvs_ctrl_max = {
        .link_mode          = E_IM_PRO_SENTOP_SLVS_LINK_CONN_PHY1,
        .phy0_rxpdck        = 0x1,
        .phy1_rxpdck        = 0x1,
        .phy2_rxpdck        = 0x1,
        .phy3_rxpdck        = 0x1,
        .phy0_rxpclk2aen    = 0x1,
        .phy1_rxpclk2aen    = 0x1,
    };

    T_IM_PRO_SENTOP_SLVS_CTRL slvs_ctrl_min = {
        .link_mode          = E_IM_PRO_SENTOP_SLVS_LINK_CONN_PHY0,
        .phy0_rxpdck        = 0,
        .phy1_rxpdck        = 0,
        .phy2_rxpdck        = 0,
        .phy3_rxpdck        = 0,
        .phy0_rxpclk2aen    = 0,
        .phy1_rxpclk2aen    = 0,
    };

    if( idx == 1 ) {
//        Ddim_Print(( "Target register address\n" ));
//        Ddim_Print(( "Im_PRO_SENTOP_SLVS_Ctrl() SLVSECCTL (0x%08lx, %lx)\n", (ULONG)&IO_PRO.SEN.SENTOP.SLVSECCTL.word, IO_PRO.SEN.SENTOP.SLVSECCTL.word    ));
        // Maximum value parameter
        ercd = Im_PRO_SENTOP_SLVS_Ctrl( &slvs_ctrl_max );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_SENTOP_SLVS_Ctrl() max_para Error ercd=0x%x\n", ercd ));
            return;
        }
        else {
            CT_Im_PRO_1_9_Print( "max_para", &slvs_ctrl_max );
        }

        // Minimum value parameter
        ercd = Im_PRO_SENTOP_SLVS_Ctrl( &slvs_ctrl_min );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_SENTOP_SLVS_Ctrl() min_para Error ercd=0x%x\n", ercd ));
            return;
        }
        else {
            CT_Im_PRO_1_9_Print( "min_para", &slvs_ctrl_min );
        }
    }
}

