VOID CT_Im_PRO_1_13_Print( const char* string )
{
    if(IO_PRO.SEN.SG[0].SGTRG.bit.SGTRG != D_IM_PRO_TRG_STATUS_RUNNING) Ddim_Print(( "Im_PRO_SG_Start() %s result:SGTRG ch0     (%d)\n", string, IO_PRO.SEN.SG[0].SGTRG.bit.SGTRG ));
    if(IO_PRO.SEN.SG[1].SGTRG.bit.SGTRG != D_IM_PRO_TRG_STATUS_RUNNING) Ddim_Print(( "Im_PRO_SG_Start() %s result:SGTRG ch1     (%d)\n", string, IO_PRO.SEN.SG[1].SGTRG.bit.SGTRG ));
    if(IO_PRO.SEN.SG[2].SGTRG.bit.SGTRG != D_IM_PRO_TRG_STATUS_RUNNING) Ddim_Print(( "Im_PRO_SG_Start() %s result:SGTRG ch2     (%d)\n", string, IO_PRO.SEN.SG[2].SGTRG.bit.SGTRG ));
    if(IO_PRO.SEN.SG[3].SGTRG.bit.SGTRG != D_IM_PRO_TRG_STATUS_RUNNING) Ddim_Print(( "Im_PRO_SG_Start() %s result:SGTRG ch3     (%d)\n", string, IO_PRO.SEN.SG[3].SGTRG.bit.SGTRG ));
}

