    if(IO_PRO.SEN.SG[ch].SGCTL2.bit.VDDLY    != sg_ctrl->vddly  ) Ddim_Print(( "Im_PRO_SG_Ctrl(%u) %s result:VDDLY    (%d) in(%d)\n", ch, string, IO_PRO.SEN.SG[ch].SGCTL2.bit.VDDLY    , sg_ctrl->vddly    ));
    if(IO_PRO.SEN.SG[ch].VDOCYC.bit.VDOCYC   != sg_ctrl->vdocyc ) Ddim_Print(( "Im_PRO_SG_Ctrl(%u) %s result:VDOCYC   (%d) in(%lu)\n", ch, string, IO_PRO.SEN.SG[ch].VDOCYC.bit.VDOCYC   , sg_ctrl->vdocyc   ));
