VOID CT_Im_PRO_1_16_Print( const char* string, E_IM_PRO_SG_CH ch, T_IM_PRO_SG_CTRL* sg_ctrl )
{
    if(sg_ctrl->vhdo   !=  IO_PRO.SEN.SG[ch].SGCTL1.bit.VHDO    ) Ddim_Print(( "Im_PRO_SG_Get_Cycle() %s result:VHDO      (%d) reg_val (%d)\n", string, sg_ctrl->vhdo,    IO_PRO.SEN.SG[ch].SGCTL1.bit.VHDO        ));
    if(sg_ctrl->vdot   !=  IO_PRO.SEN.SG[ch].SGCTL1.bit.VDOT    ) Ddim_Print(( "Im_PRO_SG_Get_Cycle() %s result:VDOT      (%d) reg_val (%d)\n", string, sg_ctrl->vdot,    IO_PRO.SEN.SG[ch].SGCTL1.bit.VDOT        ));
    if(sg_ctrl->vdinv  !=  IO_PRO.SEN.SG[ch].SGCTL1.bit.VDINV   ) Ddim_Print(( "Im_PRO_SG_Get_Cycle() %s result:VDINV     (%d) reg_val (%d)\n", string, sg_ctrl->vdinv,   IO_PRO.SEN.SG[ch].SGCTL1.bit.VDINV       ));
    if(sg_ctrl->hdinv  !=  IO_PRO.SEN.SG[ch].SGCTL1.bit.HDINV   ) Ddim_Print(( "Im_PRO_SG_Get_Cycle() %s result:HDINV     (%d) reg_val (%d)\n", string, sg_ctrl->hdinv,   IO_PRO.SEN.SG[ch].SGCTL1.bit.HDINV       ));
    if(sg_ctrl->hdchg  !=  IO_PRO.SEN.SG[ch].SGCTL2.bit.HDCHG   ) Ddim_Print(( "Im_PRO_SG_Get_Cycle() %s result:HDCHG     (%d) reg_val (%d)\n", string, sg_ctrl->hdchg,   IO_PRO.SEN.SG[ch].SGCTL2.bit.HDCHG       ));
    if(sg_ctrl->vddly  !=  IO_PRO.SEN.SG[ch].SGCTL2.bit.VDDLY   ) Ddim_Print(( "Im_PRO_SG_Get_Cycle() %s result:VDDLY     (%d) reg_val (%d)\n", string, sg_ctrl->vddly,   IO_PRO.SEN.SG[ch].SGCTL2.bit.VDDLY       ));
    if(sg_ctrl->vdocyc !=  IO_PRO.SEN.SG[ch].VDOCYC.bit.VDOCYC  ) Ddim_Print(( "Im_PRO_SG_Get_Cycle() %s result:VDOCYC    (%lu)reg_val (%d)\n", string, sg_ctrl->vdocyc,  IO_PRO.SEN.SG[ch].VDOCYC.bit.VDOCYC      ));
    if(sg_ctrl->vdow   !=  IO_PRO.SEN.SG[ch].VDOW.bit.VDOW      ) Ddim_Print(( "Im_PRO_SG_Get_Cycle() %s result:VDOW      (%d) reg_val (%d)\n", string, sg_ctrl->vdow,    IO_PRO.SEN.SG[ch].VDOW.bit.VDOW          ));
    if(sg_ctrl->hdocyc !=  IO_PRO.SEN.SG[ch].HDOCYC.bit.HDOCYC  ) Ddim_Print(( "Im_PRO_SG_Get_Cycle() %s result:HDOCYC    (%d) reg_val (%d)\n", string, sg_ctrl->hdocyc,  IO_PRO.SEN.SG[ch].HDOCYC.bit.HDOCYC      ));
    if(sg_ctrl->hdow   !=  IO_PRO.SEN.SG[ch].HDOW.bit.HDOW      ) Ddim_Print(( "Im_PRO_SG_Get_Cycle() %s result:HDOW      (%d) reg_val (%d)\n", string, sg_ctrl->hdow,    IO_PRO.SEN.SG[ch].HDOW.bit.HDOW          ));
    if(sg_ctrl->hdocyc2!=  IO_PRO.SEN.SG[ch].HDOCYC2.bit.HDOCYC2) Ddim_Print(( "Im_PRO_SG_Get_Cycle() %s result:HDOCYC2   (%d) reg_val (%d)\n", string, sg_ctrl->hdocyc2, IO_PRO.SEN.SG[ch].HDOCYC2.bit.HDOCYC2    ));
    if(sg_ctrl->hdow2  !=  IO_PRO.SEN.SG[ch].HDOW2.bit.HDOW2    ) Ddim_Print(( "Im_PRO_SG_Get_Cycle() %s result:HDOW2     (%d) reg_val (%d)\n", string, sg_ctrl->hdow2,   IO_PRO.SEN.SG[ch].HDOW2.bit.HDOW2        ));
}

