VOID CT_Im_PRO_1_23_Print( const char* string, E_IM_PRO_SLVS_STREAM_TYPE stream_type, T_IM_PRO_SLVS_CTRL* slvs_ctrl )
{
	if( stream_type > E_IM_PRO_SLVS_STREAM_TYPE_B  ) {
		return;
	}
    if(IO_PRO.SEN.SLVSEC.STREAM[stream_type].RAMPD.bit.RAMPD    != slvs_ctrl->ram_pd_state) Ddim_Print(( "Im_PRO_SLVS_Ctrl(%u) %s result:RAMPD      (%d) (%d)\n", stream_type, string, IO_PRO.SEN.SLVSEC.STREAM[stream_type].RAMPD.bit.RAMPD    , slvs_ctrl->ram_pd_state ));
    if(IO_PRO.SEN.SLVSEC.STREAM[stream_type].TRGR.bit.VDEN      != slvs_ctrl->vdout_ctrl  ) Ddim_Print(( "Im_PRO_SLVS_Ctrl(%u) %s result:VDEN       (%d) (%d)\n", stream_type, string, IO_PRO.SEN.SLVSEC.STREAM[stream_type].TRGR.bit.VDEN      , slvs_ctrl->vdout_ctrl   ));
    if(IO_PRO.SEN.SLVSEC.STREAM[stream_type].CFGR0.bit.ECCCRC   != slvs_ctrl->ecccrc_opt  ) Ddim_Print(( "Im_PRO_SLVS_Ctrl(%u) %s result:ECCCRC     (%d) (%d)\n", stream_type, string, IO_PRO.SEN.SLVSEC.STREAM[stream_type].CFGR0.bit.ECCCRC   , slvs_ctrl->ecccrc_opt   ));
    if(IO_PRO.SEN.SLVSEC.STREAM[stream_type].MMODE.bit.LNMAXCLP != slvs_ctrl->expect_val  ) Ddim_Print(( "Im_PRO_SLVS_Ctrl(%u) %s result:LNMAXCLP   (%d) (%d)\n", stream_type, string, IO_PRO.SEN.SLVSEC.STREAM[stream_type].MMODE.bit.LNMAXCLP , slvs_ctrl->expect_val   ));
}                                                                          

