	if( stream_type > E_IM_PRO_SLVS_STREAM_TYPE_B  ) {
		return;
	}
    if(IO_PRO.SEN.SLVSEC.STREAM[stream_type].CFGR0.bit.PixelBit   != mode_ctrl->pixelbit        ) Ddim_Print(( "Im_PRO_SLVS_Mode_Cfg(%u) %s result:PixelBit   (%d) (%d)\n", stream_type, string, IO_PRO.SEN.SLVSEC.STREAM[stream_type].CFGR0.bit.PixelBit   , mode_ctrl->pixelbit           ));
    if(IO_PRO.SEN.SLVSEC.STREAM[stream_type].CFGR0.bit.LaneNum    != mode_ctrl->lanenum         ) Ddim_Print(( "Im_PRO_SLVS_Mode_Cfg(%u) %s result:LaneNum    (%d) (%d)\n", stream_type, string, IO_PRO.SEN.SLVSEC.STREAM[stream_type].CFGR0.bit.LaneNum    , mode_ctrl->lanenum            ));
