    if(IO_PRO.SEN.SLVSEC.STREAM[stream_type].LSWAP.bit.L1OUT      != mode_ctrl->swap_lane[1]    ) Ddim_Print(( "Im_PRO_SLVS_Mode_Cfg(%u) %s result:L1OUT      (%d) (%d)\n", stream_type, string, IO_PRO.SEN.SLVSEC.STREAM[stream_type].LSWAP.bit.L1OUT      , mode_ctrl->swap_lane[1]       ));
