VOID CT_Im_PRO_1_25_Print( const char* string, E_IM_PRO_SLVS_STREAM_TYPE stream_type, T_IM_PRO_SLVS_TRIM_CFG* trim_ctrl )
{
	if( stream_type > E_IM_PRO_SLVS_STREAM_TYPE_B  ) {
		return;
	}
    if(IO_PRO.SEN.SLVSEC.STREAM[stream_type].OUTMD.bit.TRMG  != trim_ctrl->enabled) Ddim_Print(( "Im_PRO_SLVS_Trim_Cfg(%u) %s result:TRMG   (%d) (%d)\n", stream_type, string, IO_PRO.SEN.SLVSEC.STREAM[stream_type].OUTMD.bit.TRMG  , trim_ctrl->enabled));
    if(IO_PRO.SEN.SLVSEC.STREAM[stream_type].HSADD.bit.HSADD != trim_ctrl->start_x) Ddim_Print(( "Im_PRO_SLVS_Trim_Cfg(%u) %s result:HSADD  (%d) (%d)\n", stream_type, string, IO_PRO.SEN.SLVSEC.STREAM[stream_type].HSADD.bit.HSADD , trim_ctrl->start_x));
    if(IO_PRO.SEN.SLVSEC.STREAM[stream_type].HSIZE.bit.HSIZE != trim_ctrl->width  ) Ddim_Print(( "Im_PRO_SLVS_Trim_Cfg(%u) %s result:HSIZE  (%d) (%d)\n", stream_type, string, IO_PRO.SEN.SLVSEC.STREAM[stream_type].HSIZE.bit.HSIZE , trim_ctrl->width  ));
}

