VOID CT_Im_PRO_1_26_Print( const char* string, E_IM_PRO_SLVS_STREAM_TYPE stream_type, T_IM_PRO_SLVS_STATUS* status )
{
	if( stream_type > E_IM_PRO_SLVS_STREAM_TYPE_B  ) {
		return;
	}
    if(status->embedded_data_detect       != IO_PRO.SEN.SLVSEC.STREAM[stream_type].EBDST.bit.EBD  ) Ddim_Print(( "Im_PRO_SLVS_Get_Status(%u) %s result:VDINO (%d) reg_val (%d)\n", stream_type, string, status->embedded_data_detect,       IO_PRO.SEN.SLVSEC.STREAM[stream_type].EBDST.bit.EBD   ));
    if(status->ebd_stored_line_num        != IO_PRO.SEN.SLVSEC.STREAM[stream_type].EBDST.bit.LNUM ) Ddim_Print(( "Im_PRO_SLVS_Get_Status(%u) %s result:VDINO (%d) reg_val (%d)\n", stream_type, string, status->ebd_stored_line_num,        IO_PRO.SEN.SLVSEC.STREAM[stream_type].EBDST.bit.LNUM  ));
    if(status->expect_value_discontinuity != IO_PRO.SEN.SLVSEC.STREAM[stream_type].LNEST.bit.EXPLN) Ddim_Print(( "Im_PRO_SLVS_Get_Status(%u) %s result:VDINO (%d) reg_val (%d)\n", stream_type, string, status->expect_value_discontinuity, IO_PRO.SEN.SLVSEC.STREAM[stream_type].LNEST.bit.EXPLN ));
    if(status->line_num_discontinuity     != IO_PRO.SEN.SLVSEC.STREAM[stream_type].LNEST.bit.DETLN) Ddim_Print(( "Im_PRO_SLVS_Get_Status(%u) %s result:VDINO (%d) reg_val (%d)\n", stream_type, string, status->line_num_discontinuity,     IO_PRO.SEN.SLVSEC.STREAM[stream_type].LNEST.bit.DETLN ));
}

VOID CT_Im_PRO_1_26( const UINT32 idx )
{
    INT32                       ercd;
    E_IM_PRO_SLVS_STREAM_TYPE   stream_type;
    T_IM_PRO_SLVS_STATUS        status;

    if( idx == 1 ) {
//        Ddim_Print(( "Target register address\n" ));
//        Ddim_Print(( "Im_PRO_SLVS_Get_Status(0) EBDST  (0x%08lx, %lx)\n", (ULONG)&IO_PRO.SEN.SLVSEC.STREAM[0].EBDST.word, IO_PRO.SEN.SLVSEC.STREAM[0].EBDST.word ));
//        Ddim_Print(( "Im_PRO_SLVS_Get_Status(0) LNEST  (0x%08lx, %lx)\n", (ULONG)&IO_PRO.SEN.SLVSEC.STREAM[0].LNEST.word, IO_PRO.SEN.SLVSEC.STREAM[0].LNEST.word ));
//        Ddim_Print(( "Im_PRO_SLVS_Get_Status(1) EBDST  (0x%08lx, %lx)\n", (ULONG)&IO_PRO.SEN.SLVSEC.STREAM[1].EBDST.word, IO_PRO.SEN.SLVSEC.STREAM[1].EBDST.word ));
//        Ddim_Print(( "Im_PRO_SLVS_Get_Status(1) LNEST  (0x%08lx, %lx)\n", (ULONG)&IO_PRO.SEN.SLVSEC.STREAM[1].LNEST.word, IO_PRO.SEN.SLVSEC.STREAM[1].LNEST.word ));
        // Maximum value parameter
        stream_type = E_IM_PRO_SLVS_STREAM_TYPE_B;
#ifdef CO_DEBUG_ON_PC
        IO_PRO.SEN.SLVSEC.STREAM[stream_type].EBDST.bit.EBD     = 1;
        IO_PRO.SEN.SLVSEC.STREAM[stream_type].EBDST.bit.LNUM    = 8191;
        IO_PRO.SEN.SLVSEC.STREAM[stream_type].LNEST.bit.EXPLN   = 8191;
        IO_PRO.SEN.SLVSEC.STREAM[stream_type].LNEST.bit.DETLN   = 8191;
#endif  // CO_DEBUG_ON_PC
        ercd = Im_PRO_SLVS_Get_Status( stream_type, &status );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_SLVS_Get_Status() max_para Error ercd=0x%x\n", ercd ));
        }
        else {
            CT_Im_PRO_1_26_Print( "max_para", stream_type, &status );
        }

        stream_type = E_IM_PRO_SLVS_STREAM_TYPE_A;
#ifdef CO_DEBUG_ON_PC
        IO_PRO.SEN.SLVSEC.STREAM[stream_type].EBDST.bit.EBD     = 0;
        IO_PRO.SEN.SLVSEC.STREAM[stream_type].EBDST.bit.LNUM    = 0;
        IO_PRO.SEN.SLVSEC.STREAM[stream_type].LNEST.bit.EXPLN   = 0;
        IO_PRO.SEN.SLVSEC.STREAM[stream_type].LNEST.bit.DETLN   = 0;
#endif  // CO_DEBUG_ON_PC
        // Minimum value parameter
        ercd = Im_PRO_SLVS_Get_Status( stream_type, &status );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_SLVS_Get_Status() min_para Error ercd=0x%x\n", ercd ));
        }
        else {
            CT_Im_PRO_1_26_Print( "min_para", stream_type, &status );
        }

        // invalid value parameter
        ercd = Im_PRO_SLVS_Get_Status( stream_type, NULL );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_SLVS_Get_Status() invalid Error ercd=0x%x\n", ercd ));
        }
        else {
            CT_Im_PRO_1_26_Print( "invalid", stream_type, &status );
        }
    }
}

VOID CT_Im_PRO_1_27_Print( const char* string, E_IM_PRO_SLVS_STREAM_TYPE stream_type )
{
    if(IO_PRO.SEN.SLVSEC.STREAM[E_IM_PRO_SLVS_STREAM_TYPE_A].TRGR.bit.TRG != D_IM_PRO_TRG_STATUS_RUNNING) Ddim_Print(( "Im_PRO_SLVS_Start(%d) %s result:TRGR   (%d)\n", stream_type, string, IO_PRO.SEN.SLVSEC.STREAM[E_IM_PRO_SLVS_STREAM_TYPE_A].TRGR.bit.TRG ));
}

