VOID CT_Im_PRO_1_38_Print( const char* string, UCHAR ch, T_IM_PRO_AREA_INFO* ob_area )
{
    UCHAR block_num = 0;
    UCHAR ch_num = 0;

    im_pro_comm_get_obd_block_ch( ch, &block_num, &ch_num );
    if(IO_PRO.SEN.OBD[block_num][ch_num].OBDCORE.OBDH.bit.OBDH   != ob_area->pos_x) Ddim_Print(( "Im_PRO_OBD_Set_Area(%u) blob_num:%u ch_num:%u  %s result:OBDH     (%d) in(%d)\n", ch, block_num, ch_num, string, IO_PRO.SEN.OBD[block_num][ch_num].OBDCORE.OBDH.bit.OBDH   , ob_area->pos_x ));
    if(IO_PRO.SEN.OBD[block_num][ch_num].OBDCORE.OBDV.bit.OBDV   != ob_area->pos_y) Ddim_Print(( "Im_PRO_OBD_Set_Area(%u) blob_num:%u ch_num:%u  %s result:OBDV     (%d) in(%d)\n", ch, block_num, ch_num, string, IO_PRO.SEN.OBD[block_num][ch_num].OBDCORE.OBDV.bit.OBDV   , ob_area->pos_y ));
    if(IO_PRO.SEN.OBD[block_num][ch_num].OBDCORE.OBDHW.bit.OBDHW != ob_area->width) Ddim_Print(( "Im_PRO_OBD_Set_Area(%u) blob_num:%u ch_num:%u  %s result:OBDHW    (%d) in(%d)\n", ch, block_num, ch_num, string, IO_PRO.SEN.OBD[block_num][ch_num].OBDCORE.OBDHW.bit.OBDHW , ob_area->width ));
    if(IO_PRO.SEN.OBD[block_num][ch_num].OBDCORE.OBDVW.bit.OBDVW != ob_area->lines) Ddim_Print(( "Im_PRO_OBD_Set_Area(%u) blob_num:%u ch_num:%u  %s result:OBDVW    (%d) in(%d)\n", ch, block_num, ch_num, string, IO_PRO.SEN.OBD[block_num][ch_num].OBDCORE.OBDVW.bit.OBDVW , ob_area->lines ));
}

