VOID CT_Im_PRO_1_40_Print( const char* string, UCHAR ch, T_IM_PRO_RGB4* status )
{
    UCHAR block_num = 0;
    UCHAR ch_num = 0;

    im_pro_comm_get_obd_block_ch( ch, &block_num, &ch_num );
    if(status->R != IO_PRO.SEN.OBD[block_num][ch].OBDCORE.OBDDATAR.bit.OBDDATAR  ) Ddim_Print(( "Im_PRO_OBD_Get_OBData(%u) blob_num:%u ch_num:%u %s result:R    (%lu) reg_val (%lu)\n", ch, block_num, ch_num, string, status->R,  IO_PRO.SEN.OBD[block_num][ch].OBDCORE.OBDDATAR.bit.OBDDATAR   ));
    if(status->Gr!= IO_PRO.SEN.OBD[block_num][ch].OBDCORE.OBDDATAGR.bit.OBDDATAGR) Ddim_Print(( "Im_PRO_OBD_Get_OBData(%u) blob_num:%u ch_num:%u %s result:Gr   (%lu) reg_val (%lu)\n", ch, block_num, ch_num, string, status->Gr, IO_PRO.SEN.OBD[block_num][ch].OBDCORE.OBDDATAGR.bit.OBDDATAGR ));
    if(status->Gb!= IO_PRO.SEN.OBD[block_num][ch].OBDCORE.OBDDATAGB.bit.OBDDATAGB) Ddim_Print(( "Im_PRO_OBD_Get_OBData(%u) blob_num:%u ch_num:%u %s result:Gb   (%lu) reg_val (%lu)\n", ch, block_num, ch_num, string, status->Gb, IO_PRO.SEN.OBD[block_num][ch].OBDCORE.OBDDATAGB.bit.OBDDATAGB ));
    if(status->B != IO_PRO.SEN.OBD[block_num][ch].OBDCORE.OBDDATAB.bit.OBDDATAB  ) Ddim_Print(( "Im_PRO_OBD_Get_OBData(%u) blob_num:%u ch_num:%u %s result:B    (%lu) reg_val (%lu)\n", ch, block_num, ch_num, string, status->B,  IO_PRO.SEN.OBD[block_num][ch].OBDCORE.OBDDATAB.bit.OBDDATAB   ));
}      

