VOID CT_Im_PRO_1_42_Print( const char* string, UCHAR ch, UCHAR force )
{
    UCHAR block_num = 0;
    UCHAR ch_num = 0;

    im_pro_comm_get_obt_block_ch( ch, &block_num, &ch_num );
    if(IO_PRO.SEN.OBT[block_num][ch_num].OBTTRG.bit.OBTTRG != D_IM_PRO_TRG_STATUS_STOPPED) Ddim_Print(( "Im_PRO_OBT_Stop(%u, %u) blob_num:%u ch_num:%u  %s result:OBTTRG  (%u)\n", ch, force, block_num, ch_num, string, IO_PRO.SEN.OBT[block_num][ch_num].OBTTRG.bit.OBTTRG ));
}

