VOID CT_Im_PRO_1_44_Print( const char* string, UCHAR ch, T_IM_PRO_AREA_INFO* ob_area )
{
    UCHAR block_num = 0;
    UCHAR ch_num = 0;

    im_pro_comm_get_obt_block_ch( ch, &block_num, &ch_num );
    if(IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTH.bit.OBTH   != ob_area->pos_x) Ddim_Print(( "Im_PRO_OBT_Set_Area(%u) blob_num:%u ch_num:%u  %s result:OBTH  (%d) in(%d)\n", ch, block_num, ch_num, string, IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTH.bit.OBTH   , ob_area->pos_x ));
    if(IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTV.bit.OBTV   != ob_area->pos_y) Ddim_Print(( "Im_PRO_OBT_Set_Area(%u) blob_num:%u ch_num:%u  %s result:OBTV  (%d) in(%d)\n", ch, block_num, ch_num, string, IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTV.bit.OBTV   , ob_area->pos_y ));
    if(IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTHW.bit.OBTHW != ob_area->width) Ddim_Print(( "Im_PRO_OBT_Set_Area(%u) blob_num:%u ch_num:%u  %s result:OBTHW (%d) in(%d)\n", ch, block_num, ch_num, string, IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTHW.bit.OBTHW , ob_area->width ));
    if(IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTVW.bit.OBTVW != ob_area->lines) Ddim_Print(( "Im_PRO_OBT_Set_Area(%u) blob_num:%u ch_num:%u  %s result:OBTVW (%d) in(%d)\n", ch, block_num, ch_num, string, IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTVW.bit.OBTVW , ob_area->lines ));
}

