VOID CT_Im_PRO_1_45_Print( const char* string, UCHAR ch, T_IM_PRO_RGB2* offset )
{
    UCHAR block_num = 0;
    UCHAR ch_num = 0;

    im_pro_comm_get_obt_block_ch( ch, &block_num, &ch_num );
    if(IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTOFSR.bit.OBTOFSR   != offset->R ) Ddim_Print(( "Im_PRO_OBT_Set_Offset(%u) blob_num:%u ch_num:%u  %s result:OBTOFSR (%d) in(%d)\n", ch, block_num, ch_num, string, IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTOFSR.bit.OBTOFSR   , offset->R  ));
    if(IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTOFSGR.bit.OBTOFSGR != offset->Gr) Ddim_Print(( "Im_PRO_OBT_Set_Offset(%u) blob_num:%u ch_num:%u  %s result:OBTOFSGR(%d) in(%d)\n", ch, block_num, ch_num, string, IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTOFSGR.bit.OBTOFSGR , offset->Gr ));
    if(IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTOFSGB.bit.OBTOFSGB != offset->Gb) Ddim_Print(( "Im_PRO_OBT_Set_Offset(%u) blob_num:%u ch_num:%u  %s result:OBTOFSGB(%d) in(%d)\n", ch, block_num, ch_num, string, IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTOFSGB.bit.OBTOFSGB , offset->Gb ));
    if(IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTOFSB.bit.OBTOFSB   != offset->B ) Ddim_Print(( "Im_PRO_OBT_Set_Offset(%u) blob_num:%u ch_num:%u  %s result:OBTOFSB (%d) in(%d)\n", ch, block_num, ch_num, string, IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTOFSB.bit.OBTOFSB   , offset->B  ));
}

