VOID CT_Im_PRO_1_47_Print( const char* string, UCHAR ch, const T_IM_PRO_RDMA_OBT_ADDR** addr )
{
    UCHAR block_num = 0;
    UCHAR ch_num = 0;

    im_pro_comm_get_obt_block_ch( ch, &block_num, &ch_num );
    if((ULONG)&IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTCTL.word   != (*addr)->OBTCTL  ) Ddim_Print(( "Im_PRO_Get_RdmaAddr_OBT_Cntl(%u) blob_num:%u ch_num:%u %s OBTCTL      reg_addr (0x%08lx) rdma_addr (0x%08lx)\n", ch, block_num, ch_num, string, (ULONG)&IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTCTL.word   , (ULONG)(*addr)->OBTCTL    ));
    if((ULONG)&IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTTHBIT.word != (*addr)->OBTTHBIT) Ddim_Print(( "Im_PRO_Get_RdmaAddr_OBT_Cntl(%u) blob_num:%u ch_num:%u %s OBTTHBIT    reg_addr (0x%08lx) rdma_addr (0x%08lx)\n", ch, block_num, ch_num, string, (ULONG)&IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTTHBIT.word , (ULONG)(*addr)->OBTTHBIT  ));
    if((ULONG)&IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTOFSR.word  != (*addr)->OBTOFSR ) Ddim_Print(( "Im_PRO_Get_RdmaAddr_OBT_Cntl(%u) blob_num:%u ch_num:%u %s OBTOFSR     reg_addr (0x%08lx) rdma_addr (0x%08lx)\n", ch, block_num, ch_num, string, (ULONG)&IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTOFSR.word  , (ULONG)(*addr)->OBTOFSR   ));
    if((ULONG)&IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTOFSGR.word != (*addr)->OBTOFSGR) Ddim_Print(( "Im_PRO_Get_RdmaAddr_OBT_Cntl(%u) blob_num:%u ch_num:%u %s OBTOFSGR    reg_addr (0x%08lx) rdma_addr (0x%08lx)\n", ch, block_num, ch_num, string, (ULONG)&IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTOFSGR.word , (ULONG)(*addr)->OBTOFSGR  ));
    if((ULONG)&IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTOFSGB.word != (*addr)->OBTOFSGB) Ddim_Print(( "Im_PRO_Get_RdmaAddr_OBT_Cntl(%u) blob_num:%u ch_num:%u %s OBTOFSGB    reg_addr (0x%08lx) rdma_addr (0x%08lx)\n", ch, block_num, ch_num, string, (ULONG)&IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTOFSGB.word , (ULONG)(*addr)->OBTOFSGB  ));
    if((ULONG)&IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTOFSB.word  != (*addr)->OBTOFSB ) Ddim_Print(( "Im_PRO_Get_RdmaAddr_OBT_Cntl(%u) blob_num:%u ch_num:%u %s OBTOFSB     reg_addr (0x%08lx) rdma_addr (0x%08lx)\n", ch, block_num, ch_num, string, (ULONG)&IO_PRO.SEN.OBT[block_num][ch_num].OBTCORE.OBTOFSB.word  , (ULONG)(*addr)->OBTOFSB   ));
}

VOID CT_Im_PRO_1_47( const UINT32 idx )
{
    INT32                           ercd;
    E_IM_PRO_OBT_CH                 ch;
    const T_IM_PRO_RDMA_OBT_ADDR*   addr;

    if( idx == 1 ) {
        // max parameter
        ch = E_IM_PRO_OBT_CH_3_1;
        ercd = Im_PRO_Get_RdmaAddr_OBT_Cntl( ch, &addr );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_Get_RdmaAddr_OBT_Cntl() Error ercd=0x%x\n", ercd ));
        }
        else {
            CT_Im_PRO_1_47_Print( "max_para", ch, &addr );
        }

        // min parameter
        ch = E_IM_PRO_OBT_CH_0_0;
        ercd = Im_PRO_Get_RdmaAddr_OBT_Cntl( ch, &addr );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_Get_RdmaAddr_OBT_Cntl() Error ercd=0x%x\n", ercd ));
        }
        else {
            CT_Im_PRO_1_47_Print( "min_para", ch, &addr );
        }

        // invalid value parameter
        ercd = Im_PRO_OBT_Get_OBTData( ch, NULL );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_Get_RdmaAddr_OBT_Cntl() invalid Error ercd=0x%x\n", ercd ));
        }
        else {
            CT_Im_PRO_1_47_Print( "invalid", ch, &addr );
        }

    }
}

