VOID CT_Im_PRO_1_59_Print( const char* string, UCHAR ch, T_IM_PRO_CMIPI_CTRL* cmipi_ctrl )
{
    if(IO_PRO.SEN.MIPIC[ch].MPICLMODE.bit.LANE               != cmipi_ctrl->lane_sel             ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:LANE              (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICLMODE.bit.LANE               , cmipi_ctrl->lane_sel              ));
    if(IO_PRO.SEN.MIPIC[ch].MPICIOMD0.bit.DTMD0              != cmipi_ctrl->input_data_mode[0]   ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:DTMD0             (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICIOMD0.bit.DTMD0              , cmipi_ctrl->input_data_mode[0]    ));
    if(IO_PRO.SEN.MIPIC[ch].MPICIOMD0.bit.OUTMD0             != cmipi_ctrl->output_data_mode[0]  ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:OUTMD0            (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICIOMD0.bit.OUTMD0             , cmipi_ctrl->output_data_mode[0]   ));
    if(IO_PRO.SEN.MIPIC[ch].MPICIOMD0.bit.VCOUT0             != cmipi_ctrl->vc_mode_sel[0]       ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:VCOUT0            (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICIOMD0.bit.VCOUT0             , cmipi_ctrl->vc_mode_sel[0]        ));
    if(IO_PRO.SEN.MIPIC[ch].MPICIOMD0.bit.DTCOMD0            != cmipi_ctrl->output_dt_sel[0]     ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:DTCOMD0           (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICIOMD0.bit.DTCOMD0            , cmipi_ctrl->output_dt_sel[0]      ));
    if(IO_PRO.SEN.MIPIC[ch].MPICIOMD0.bit.DTCO0              != cmipi_ctrl->output_dt_setting[0] ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:DTCO0             (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICIOMD0.bit.DTCO0              , cmipi_ctrl->output_dt_setting[0]  ));
    if(IO_PRO.SEN.MIPIC[ch].MPICIOMD1.bit.DTMD1              != cmipi_ctrl->input_data_mode[1]   ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:DTMD1             (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICIOMD1.bit.DTMD1              , cmipi_ctrl->input_data_mode[1]    ));
    if(IO_PRO.SEN.MIPIC[ch].MPICIOMD1.bit.OUTMD1             != cmipi_ctrl->output_data_mode[1]  ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:OUTMD1            (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICIOMD1.bit.OUTMD1             , cmipi_ctrl->output_data_mode[1]   ));
    if(IO_PRO.SEN.MIPIC[ch].MPICIOMD1.bit.VCOUT1             != cmipi_ctrl->vc_mode_sel[1]       ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:VCOUT1            (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICIOMD1.bit.VCOUT1             , cmipi_ctrl->vc_mode_sel[1]        ));
    if(IO_PRO.SEN.MIPIC[ch].MPICIOMD1.bit.DTCOMD1            != cmipi_ctrl->output_dt_sel[1]     ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:DTCOMD1           (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICIOMD1.bit.DTCOMD1            , cmipi_ctrl->output_dt_sel[1]      ));
    if(IO_PRO.SEN.MIPIC[ch].MPICIOMD1.bit.DTCO1              != cmipi_ctrl->output_dt_setting[1] ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:DTCO1             (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICIOMD1.bit.DTCO1              , cmipi_ctrl->output_dt_setting[1]  ));
    if(IO_PRO.SEN.MIPIC[ch].MPICHDPDSEL.bit.HDPDSEL0         != cmipi_ctrl->out_cycle[0]         ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:HDPDSEL0          (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICHDPDSEL.bit.HDPDSEL0         , cmipi_ctrl->out_cycle[0]          ));
    if(IO_PRO.SEN.MIPIC[ch].MPICHDPDSEL.bit.HDPDSEL1         != cmipi_ctrl->out_cycle[1]         ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:HDPDSEL1          (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICHDPDSEL.bit.HDPDSEL1         , cmipi_ctrl->out_cycle[1]          ));
    if(IO_PRO.SEN.MIPIC[ch].MPICCPI2.bit.CP_HS_SETTLECNT     != cmipi_ctrl->phy_ctrl.hs_settlecnt) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:CP_HS_SETTLECNT   (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICCPI2.bit.CP_HS_SETTLECNT     , cmipi_ctrl->phy_ctrl.hs_settlecnt ));
    if(IO_PRO.SEN.MIPIC[ch].MPICCPI2.bit.CP_HS_STOPCNT       != cmipi_ctrl->phy_ctrl.hs_stopcnt  ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:CP_HS_STOPCNT     (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICCPI2.bit.CP_HS_STOPCNT       , cmipi_ctrl->phy_ctrl.hs_stopcnt   ));
    if(IO_PRO.SEN.MIPIC[ch].MPICCPI2.bit.CP_HS_SYNCMODE      != cmipi_ctrl->phy_ctrl.hs_syncmode ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:CP_HS_SYNCMODE    (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICCPI2.bit.CP_HS_SYNCMODE      , cmipi_ctrl->phy_ctrl.hs_syncmode  ));
    if(IO_PRO.SEN.MIPIC[ch].MPICPRLRLCONF.bit.CP_RLR_LCONFIG != cmipi_ctrl->phy_ctrl.rlr_lconfig ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:CP_RLR_LCONFIG    (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICPRLRLCONF.bit.CP_RLR_LCONFIG , cmipi_ctrl->phy_ctrl.rlr_lconfig  ));
    if(IO_PRO.SEN.MIPIC[ch].MPICPRLRLTPSEL.bit.CP_RLR_TPSEL  != cmipi_ctrl->phy_ctrl.rlr_tpsel   ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:CP_RLR_TPSEL      (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICPRLRLTPSEL.bit.CP_RLR_TPSEL  , cmipi_ctrl->phy_ctrl.rlr_tpsel    ));
    if(IO_PRO.SEN.MIPIC[ch].MPICPRLRPRBS.bit.CP_RLR_PRBSSP   != cmipi_ctrl->phy_ctrl.rlr_prbssp  ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:CP_RLR_PRBSSP     (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICPRLRPRBS.bit.CP_RLR_PRBSSP   , cmipi_ctrl->phy_ctrl.rlr_prbssp   ));
    if(IO_PRO.SEN.MIPIC[ch].MPICPPROGSEQ.bit.CP_TGR_PROGSEQ  != cmipi_ctrl->phy_ctrl.tgr_progseq ) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:CP_TGR_PROGSEQ    (%llu) (%llu)\n", ch, string, (ULLONG)IO_PRO.SEN.MIPIC[ch].MPICPPROGSEQ.bit.CP_TGR_PROGSEQ  , (ULLONG)cmipi_ctrl->phy_ctrl.tgr_progseq  ));
    if(IO_PRO.SEN.MIPIC[ch].MPICPFRXMODE.bit.CP_FORCERXMODE2 != cmipi_ctrl->phy_ctrl.forcerxmode2) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:CP_FORCERXMODE2   (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICPFRXMODE.bit.CP_FORCERXMODE2 , cmipi_ctrl->phy_ctrl.forcerxmode2 ));
    if(IO_PRO.SEN.MIPIC[ch].MPICPFRXMODE.bit.CP_FORCERXMODE1 != cmipi_ctrl->phy_ctrl.forcerxmode1) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:CP_FORCERXMODE1   (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICPFRXMODE.bit.CP_FORCERXMODE1 , cmipi_ctrl->phy_ctrl.forcerxmode1 ));
    if(IO_PRO.SEN.MIPIC[ch].MPICPFRXMODE.bit.CP_FORCERXMODE0 != cmipi_ctrl->phy_ctrl.forcerxmode0) Ddim_Print(( "Im_PRO_CMIPI_Ctrl(%u) %s result:CP_FORCERXMODE0   (%d) (%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICPFRXMODE.bit.CP_FORCERXMODE0 , cmipi_ctrl->phy_ctrl.forcerxmode0 ));
}

VOID CT_Im_PRO_1_59( const UINT32 idx )
{
    INT32 ercd;
    UCHAR               ch;
    T_IM_PRO_CMIPI_CTRL cmipi_ctrl_max = {
        .lane_sel               = E_IM_PRO_CMIPI_LANE_4,
        .input_data_mode[0]     = E_IM_PRO_CMIPI_IN_DATA_MODE_USER_DEF,
        .output_data_mode[0]    = E_IM_PRO_CMIPI_OUT_MODE_8POINT,
        .vc_mode_sel[0]         = E_IM_PRO_CMIPI_VC_INVALID,
        .output_dt_sel[0]       = E_IM_PRO_CMIPI_DT_OUT_EN,
        .output_dt_setting[0]   = 63,
        .input_data_mode[1]     = E_IM_PRO_CMIPI_IN_DATA_MODE_USER_DEF,
        .output_data_mode[1]    = E_IM_PRO_CMIPI_OUT_MODE_8POINT,
        .vc_mode_sel[1]         = E_IM_PRO_CMIPI_VC_INVALID,
        .output_dt_sel[1]       = E_IM_PRO_CMIPI_DT_OUT_EN,
        .output_dt_setting[1]   = 63,
        .out_cycle[0]           = E_IM_PRO_CMIPI_SEL_CYCLE_2,
        .out_cycle[1]           = E_IM_PRO_CMIPI_SEL_CYCLE_2,
        .phy_ctrl.hs_settlecnt  = 15,
        .phy_ctrl.hs_stopcnt    = 31,
        .phy_ctrl.hs_syncmode   = 1,
        .phy_ctrl.rlr_lconfig   = 255,
        .phy_ctrl.rlr_tpsel     = 255,
        .phy_ctrl.rlr_prbssp    = 255,
        .phy_ctrl.tgr_progseq   = 0x20000000000,
        .phy_ctrl.forcerxmode2  = 1,
        .phy_ctrl.forcerxmode1  = 1,
        .phy_ctrl.forcerxmode0  = 1,
    };

    T_IM_PRO_CMIPI_CTRL cmipi_ctrl_min = {
        .lane_sel               = E_IM_PRO_CMIPI_LANE_1,
        .input_data_mode[0]     = E_IM_PRO_CMIPI_IN_DATA_MODE_8BIT,
        .output_data_mode[0]    = E_IM_PRO_CMIPI_OUT_MODE_NO_OUTPUT,
        .vc_mode_sel[0]         = E_IM_PRO_CMIPI_VC_0,
        .output_dt_sel[0]       = E_IM_PRO_CMIPI_DT_OUT_DIS,
        .output_dt_setting[0]   = 0,
        .input_data_mode[1]     = E_IM_PRO_CMIPI_IN_DATA_MODE_8BIT,
        .output_data_mode[1]    = E_IM_PRO_CMIPI_OUT_MODE_NO_OUTPUT,
        .vc_mode_sel[1]         = E_IM_PRO_CMIPI_VC_0,
        .output_dt_sel[1]       = E_IM_PRO_CMIPI_DT_OUT_DIS,
        .output_dt_setting[1]   = 0,
        .out_cycle[0]           = E_IM_PRO_CMIPI_SEL_CYCLE_0,
        .out_cycle[1]           = E_IM_PRO_CMIPI_SEL_CYCLE_0,
        .phy_ctrl.hs_settlecnt  = 0,
        .phy_ctrl.hs_stopcnt    = 0,
        .phy_ctrl.hs_syncmode   = 0,
        .phy_ctrl.rlr_lconfig   = 0,
        .phy_ctrl.rlr_tpsel     = 0,
        .phy_ctrl.rlr_prbssp    = 0,
        .phy_ctrl.tgr_progseq   = 0,
        .phy_ctrl.forcerxmode2  = 0,
        .phy_ctrl.forcerxmode1  = 0,
        .phy_ctrl.forcerxmode0  = 0,
    };

    if( idx == 1 ) {
//        Ddim_Print(( "Target register address\n" ));
//        Ddim_Print(( "Im_PRO_CMIPI_Ctrl(0) MPICLMODE        (0x%08lx, %lx)\n",  (ULONG)&IO_PRO.SEN.MIPIC[0].MPICLMODE.word ,       IO_PRO.SEN.MIPIC[0].MPICLMODE.word  ));
        // Maximum value parameter
        ch = E_IM_PRO_CMIPI_CH3;
        ercd = Im_PRO_CMIPI_Ctrl( ch, &cmipi_ctrl_max );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_CMIPI_Ctrl() max_para Error ercd=0x%x\n", ercd ));
        }
        else {
            CT_Im_PRO_1_59_Print( "max_para", ch, &cmipi_ctrl_max );
        }

        // Minimum value parameter
        ch = E_IM_PRO_CMIPI_CH0;
        ercd = Im_PRO_CMIPI_Ctrl( ch, &cmipi_ctrl_min );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_CMIPI_Ctrl() min_para Error ercd=0x%x\n", ercd ));
        }
        else {
            CT_Im_PRO_1_59_Print( "min_para", ch, &cmipi_ctrl_min );
        }
    }
}

VOID CT_Im_PRO_1_60_Print( const char* string, UCHAR ch, UCHAR paen_trg0, UCHAR paen_trg1 )
{
    if(IO_PRO.SEN.MIPIC[ch].MPICPAEN0.bit.PAEN0 != paen_trg0) Ddim_Print(( "Im_PRO_CMIPI_Set_PAEN(%u) %s result:PAEN0(%d) MPICTRG(%d) paen_trg0(%d) paen_trg1(%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICPAEN0.bit.PAEN0, IO_PRO.SEN.MIPIC[ch].MPICTRG.bit.MPICTRG, paen_trg0, paen_trg1 ));
    if(IO_PRO.SEN.MIPIC[ch].MPICPAEN1.bit.PAEN1 != paen_trg1) Ddim_Print(( "Im_PRO_CMIPI_Set_PAEN(%u) %s result:PAEN1(%d) MPICTRG(%d) paen_trg0(%d) paen_trg1(%d)\n", ch, string, IO_PRO.SEN.MIPIC[ch].MPICPAEN1.bit.PAEN1, IO_PRO.SEN.MIPIC[ch].MPICTRG.bit.MPICTRG, paen_trg0, paen_trg1 ));
}
VOID CT_Im_PRO_1_60( const UINT32 idx )
{
    INT32               ercd;
    UCHAR               paen_trg0;
    UCHAR               paen_trg1;
    UCHAR               ch;

    if( idx == 1 ) {
//        Ddim_Print(( "Target register address\n" ));
//        Ddim_Print(( "Im_PRO_CMIPI_Set_PAEN(0) MPICPAEN0    (0x%08lx, %lx)\n", (ULONG)&IO_PRO.SEN.MIPIC[0].MPICPAEN0.word, IO_PRO.SEN.MIPIC[0].MPICPAEN0.word  ));
//        Ddim_Print(( "Im_PRO_CMIPI_Set_PAEN(0) MPICPAEN1    (0x%08lx, %lx)\n", (ULONG)&IO_PRO.SEN.MIPIC[0].MPICPAEN1.word, IO_PRO.SEN.MIPIC[0].MPICPAEN1.word  ));
//        Ddim_Print(( "Im_PRO_CMIPI_Set_PAEN(1) MPICPAEN0    (0x%08lx, %lx)\n", (ULONG)&IO_PRO.SEN.MIPIC[1].MPICPAEN0.word, IO_PRO.SEN.MIPIC[1].MPICPAEN0.word  ));
//        Ddim_Print(( "Im_PRO_CMIPI_Set_PAEN(1) MPICPAEN1    (0x%08lx, %lx)\n", (ULONG)&IO_PRO.SEN.MIPIC[1].MPICPAEN1.word, IO_PRO.SEN.MIPIC[1].MPICPAEN1.word  ));
//        Ddim_Print(( "Im_PRO_CMIPI_Set_PAEN(2) MPICPAEN0    (0x%08lx, %lx)\n", (ULONG)&IO_PRO.SEN.MIPIC[2].MPICPAEN0.word, IO_PRO.SEN.MIPIC[2].MPICPAEN0.word  ));
//        Ddim_Print(( "Im_PRO_CMIPI_Set_PAEN(2) MPICPAEN1    (0x%08lx, %lx)\n", (ULONG)&IO_PRO.SEN.MIPIC[2].MPICPAEN1.word, IO_PRO.SEN.MIPIC[2].MPICPAEN1.word  ));
//        Ddim_Print(( "Im_PRO_CMIPI_Set_PAEN(3) MPICPAEN0    (0x%08lx, %lx)\n", (ULONG)&IO_PRO.SEN.MIPIC[3].MPICPAEN0.word, IO_PRO.SEN.MIPIC[3].MPICPAEN0.word  ));
//        Ddim_Print(( "Im_PRO_CMIPI_Set_PAEN(3) MPICPAEN1    (0x%08lx, %lx)\n", (ULONG)&IO_PRO.SEN.MIPIC[3].MPICPAEN1.word, IO_PRO.SEN.MIPIC[3].MPICPAEN1.word  ));

        // enable value parameter
        ch = E_IM_PRO_CMIPI_CH3;
        paen_trg0 = 1;
        paen_trg1 = 1;
        ercd = Im_PRO_CMIPI_Set_PAEN( ch, paen_trg0, paen_trg1 );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_CMIPI_Set_PAEN() max_para Error ercd=0x%x\n", ercd ));
        }
        else {
            CT_Im_PRO_1_60_Print( "max_para", ch, paen_trg0, paen_trg1 );
        }

        // disable value parameter
        ch = E_IM_PRO_CMIPI_CH0;
        paen_trg0 = 0;
        paen_trg1 = 0;
        ercd = Im_PRO_CMIPI_Set_PAEN( ch, paen_trg0, paen_trg1 );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_CMIPI_Set_PAEN() min_para Error ercd=0x%x\n", ercd ));
        }
        else {
            CT_Im_PRO_1_60_Print( "min_para", ch, paen_trg0, paen_trg1 );
        }

        // macro running error test
        ch = E_IM_PRO_CMIPI_CH0;
        paen_trg0 = 0;
        paen_trg1 = 0;
#ifdef CO_DEBUG_ON_PC
        IO_PRO.SEN.MIPIC[ch].MPICTRG.bit.MPICTRG = D_IM_PRO_TRG_STATUS_RUNNING;
#else
        Im_PRO_CMIPI_Start( ch );
#endif
        ercd = Im_PRO_CMIPI_Set_PAEN( ch, paen_trg0, paen_trg1 );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_CMIPI_Set_PAEN() min_para Error ercd=0x%x\n", ercd ));
        }
        else {
            CT_Im_PRO_1_60_Print( "macro running error", ch, paen_trg0, paen_trg1 );
        }
#ifdef CO_DEBUG_ON_PC
        IO_PRO.SEN.MIPIC[ch].MPICTRG.bit.MPICTRG = D_IM_PRO_TRG_STATUS_STOPPED;
#else
        Im_PRO_CMIPI_Stop( ch, 0 );
#endif
    }
}

VOID CT_Im_PRO_1_61_Print( const char* string, UCHAR ch, T_IM_PRO_CMIPI_STATUS* status )
{
    if(status->rxstopstate_l0 != IO_PRO.SEN.MIPIC[ch].MPICPVR.bit.SSL0                     ) Ddim_Print(( "Im_PRO_CMIPI_Get_Status(%u) %s result:SSL0                (%d) reg_val (%u)\n", ch, string, status->rxstopstate_l0,       IO_PRO.SEN.MIPIC[ch].MPICPVR.bit.SSL0                       ));
    if(status->rxstopstate_l1 != IO_PRO.SEN.MIPIC[ch].MPICPVR.bit.SSL1                     ) Ddim_Print(( "Im_PRO_CMIPI_Get_Status(%u) %s result:SSL1                (%d) reg_val (%u)\n", ch, string, status->rxstopstate_l1,       IO_PRO.SEN.MIPIC[ch].MPICPVR.bit.SSL1                       ));
    if(status->rxstopstate_l2 != IO_PRO.SEN.MIPIC[ch].MPICPVR.bit.SSL2                     ) Ddim_Print(( "Im_PRO_CMIPI_Get_Status(%u) %s result:SSL2                (%d) reg_val (%u)\n", ch, string, status->rxstopstate_l2,       IO_PRO.SEN.MIPIC[ch].MPICPVR.bit.SSL2                       ));
    if(status->lstatus0       != IO_PRO.SEN.MIPIC[ch].MPICPRLRLST.bit.CP_RLR_LSTATUS0      ) Ddim_Print(( "Im_PRO_CMIPI_Get_Status(%u) %s result:CP_RLR_LSTATUS0     (%d) reg_val (%u)\n", ch, string, status->lstatus0      ,       IO_PRO.SEN.MIPIC[ch].MPICPRLRLST.bit.CP_RLR_LSTATUS0        ));
    if(status->lstatus1       != IO_PRO.SEN.MIPIC[ch].MPICPRLRLST.bit.CP_RLR_LSTATUS1      ) Ddim_Print(( "Im_PRO_CMIPI_Get_Status(%u) %s result:CP_RLR_LSTATUS1     (%d) reg_val (%u)\n", ch, string, status->lstatus1      ,       IO_PRO.SEN.MIPIC[ch].MPICPRLRLST.bit.CP_RLR_LSTATUS1        ));
    if(status->lstatus2       != IO_PRO.SEN.MIPIC[ch].MPICPRLRLST.bit.CP_RLR_LSTATUS2      ) Ddim_Print(( "Im_PRO_CMIPI_Get_Status(%u) %s result:CP_RLR_LSTATUS2     (%d) reg_val (%u)\n", ch, string, status->lstatus2      ,       IO_PRO.SEN.MIPIC[ch].MPICPRLRLST.bit.CP_RLR_LSTATUS2        ));
    if(status->werrcnt0       != IO_PRO.SEN.MIPIC[ch].MPICPRLRWECNT0.bit.CP_RLR_WERRCNT0   ) Ddim_Print(( "Im_PRO_CMIPI_Get_Status(%u) %s result:CP_RLR_WERRCNT0     (%d) reg_val (%u)\n", ch, string, status->werrcnt0      ,       IO_PRO.SEN.MIPIC[ch].MPICPRLRWECNT0.bit.CP_RLR_WERRCNT0     ));
    if(status->werrcnt1       != IO_PRO.SEN.MIPIC[ch].MPICPRLRWECNT1.bit.CP_RLR_WERRCNT1   ) Ddim_Print(( "Im_PRO_CMIPI_Get_Status(%u) %s result:CP_RLR_WERRCNT1     (%d) reg_val (%u)\n", ch, string, status->werrcnt1      ,       IO_PRO.SEN.MIPIC[ch].MPICPRLRWECNT1.bit.CP_RLR_WERRCNT1     ));
    if(status->werrcnt2       != IO_PRO.SEN.MIPIC[ch].MPICPRLRWECNT2.bit.CP_RLR_WERRCNT2   ) Ddim_Print(( "Im_PRO_CMIPI_Get_Status(%u) %s result:CP_RLR_WERRCNT2     (%d) reg_val (%u)\n", ch, string, status->werrcnt2      ,       IO_PRO.SEN.MIPIC[ch].MPICPRLRWECNT2.bit.CP_RLR_WERRCNT2     ));
    if(status->wcnt0          != IO_PRO.SEN.MIPIC[ch].MPICPRLRWCNT0.bit.CP_RLR_WCNT0       ) Ddim_Print(( "Im_PRO_CMIPI_Get_Status(%u) %s result:CP_RLR_WCNT0        (%lld) reg_val (%lld)\n", ch, string, status->wcnt0     ,       (ULLONG)IO_PRO.SEN.MIPIC[ch].MPICPRLRWCNT0.bit.CP_RLR_WCNT0         ));
    if(status->wcnt1          != IO_PRO.SEN.MIPIC[ch].MPICPRLRWCNT1.bit.CP_RLR_WCNT1       ) Ddim_Print(( "Im_PRO_CMIPI_Get_Status(%u) %s result:CP_RLR_WCNT1        (%lld) reg_val (%lld)\n", ch, string, status->wcnt1     ,       (ULLONG)IO_PRO.SEN.MIPIC[ch].MPICPRLRWCNT1.bit.CP_RLR_WCNT1         ));
    if(status->wcnt2          != IO_PRO.SEN.MIPIC[ch].MPICPRLRWCNT2.bit.CP_RLR_WCNT2       ) Ddim_Print(( "Im_PRO_CMIPI_Get_Status(%u) %s result:CP_RLR_WCNT2        (%lld) reg_val (%lld)\n", ch, string, status->wcnt2     ,       (ULLONG)IO_PRO.SEN.MIPIC[ch].MPICPRLRWCNT2.bit.CP_RLR_WCNT2         ));
    if(status->syerrcnt0      != IO_PRO.SEN.MIPIC[ch].MPICPRLRSERRCNT0.bit.CP_RLR_SYERRCNT0) Ddim_Print(( "Im_PRO_CMIPI_Get_Status(%u) %s result:CP_RLR_SYERRCNT0    (%d) reg_val (%u)\n", ch, string, status->syerrcnt0     ,       IO_PRO.SEN.MIPIC[ch].MPICPRLRSERRCNT0.bit.CP_RLR_SYERRCNT0  ));
    if(status->syerrcnt1      != IO_PRO.SEN.MIPIC[ch].MPICPRLRSERRCNT1.bit.CP_RLR_SYERRCNT1) Ddim_Print(( "Im_PRO_CMIPI_Get_Status(%u) %s result:CP_RLR_SYERRCNT1    (%d) reg_val (%u)\n", ch, string, status->syerrcnt1     ,       IO_PRO.SEN.MIPIC[ch].MPICPRLRSERRCNT1.bit.CP_RLR_SYERRCNT1  ));
    if(status->syerrcnt2      != IO_PRO.SEN.MIPIC[ch].MPICPRLRSERRCNT2.bit.CP_RLR_SYERRCNT2) Ddim_Print(( "Im_PRO_CMIPI_Get_Status(%u) %s result:CP_RLR_SYERRCNT2    (%d) reg_val (%u)\n", ch, string, status->syerrcnt2     ,       IO_PRO.SEN.MIPIC[ch].MPICPRLRSERRCNT2.bit.CP_RLR_SYERRCNT2  ));
    if(status->syerrloc0      != IO_PRO.SEN.MIPIC[ch].MPICPRLRSERRLOC0.bit.CP_RLR_SYERRLOC0) Ddim_Print(( "Im_PRO_CMIPI_Get_Status(%u) %s result:CP_RLR_SYERRLOC0    (%llu) reg_val (%llu)\n", ch, string, status->syerrloc0     ,   (ULLONG)IO_PRO.SEN.MIPIC[ch].MPICPRLRSERRLOC0.bit.CP_RLR_SYERRLOC0  ));
    if(status->syerrloc1      != IO_PRO.SEN.MIPIC[ch].MPICPRLRSERRLOC1.bit.CP_RLR_SYERRLOC1) Ddim_Print(( "Im_PRO_CMIPI_Get_Status(%u) %s result:CP_RLR_SYERRLOC1    (%llu) reg_val (%llu)\n", ch, string, status->syerrloc1     ,   (ULLONG)IO_PRO.SEN.MIPIC[ch].MPICPRLRSERRLOC1.bit.CP_RLR_SYERRLOC1  ));
    if(status->syerrloc2      != IO_PRO.SEN.MIPIC[ch].MPICPRLRSERRLOC2.bit.CP_RLR_SYERRLOC2) Ddim_Print(( "Im_PRO_CMIPI_Get_Status(%u) %s result:CP_RLR_SYERRLOC2    (%llu) reg_val (%llu)\n", ch, string, status->syerrloc2     ,   (ULLONG)IO_PRO.SEN.MIPIC[ch].MPICPRLRSERRLOC2.bit.CP_RLR_SYERRLOC2  ));
}

