VOID CT_Im_PRO_1_62_Print( const char* string, UCHAR ch )
{
    if(IO_PRO.SEN.LVDS[ch].LVDSTRG.bit.LVDSTRG != D_IM_PRO_TRG_STATUS_RUNNING) Ddim_Print(( "Im_PRO_LVDS_Start(%u) %s result:LVDSTRG   (%u)\n", ch, string, IO_PRO.SEN.LVDS[ch].LVDSTRG.bit.LVDSTRG ));
}

VOID CT_Im_PRO_1_62( const UINT32 idx )
{
    INT32               ercd;
    UCHAR               ch;

    if( idx == 1 ) {
        // max parameter
        ch = E_IM_PRO_LVDS_CH_3;
        ercd = Im_PRO_LVDS_Start( ch );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_LVDS_Start(%u) Error ercd=0x%x\n", ch, ercd ));
        }
        else {
            CT_Im_PRO_1_62_Print( "max_para", ch );
        }

        // min parameter
        ch = E_IM_PRO_LVDS_CH_0;
        ercd = Im_PRO_LVDS_Start( ch );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_LVDS_Start(%u) Error ercd=0x%x\n", ch, ercd ));
        }
        else {
            CT_Im_PRO_1_62_Print( "min_para", ch );
        }
    }
}

VOID CT_Im_PRO_1_63_Print( const char* string, UCHAR ch )
{
    if(IO_PRO.SEN.LVDS[ch].LVDSTRG.bit.LVDSTRG != D_IM_PRO_TRG_STATUS_STOPPED) Ddim_Print(( "Im_PRO_LVDS_Stop(%u) %s result:LVDSTRG    (%u)\n", ch, string, IO_PRO.SEN.LVDS[ch].LVDSTRG.bit.LVDSTRG ));
}

