VOID CT_Im_PRO_1_65_Print( const char* string, UCHAR ch, USHORT input_pos, USHORT input_size )
{
    if(IO_PRO.SEN.LVDS[ch].LHSADD.bit.LHSADD != input_pos ) Ddim_Print(( "Im_PRO_LVDS_Set_Area(%u) %s result:LHSADD(%d) in(%d)\n", ch, string, IO_PRO.SEN.LVDS[ch].LHSADD.bit.LHSADD, input_pos ));
    if(IO_PRO.SEN.LVDS[ch].LHSIZE.bit.LHSIZE != input_size) Ddim_Print(( "Im_PRO_LVDS_Set_Area(%u) %s result:LHSIZE(%d) in(%d)\n", ch, string, IO_PRO.SEN.LVDS[ch].LHSIZE.bit.LHSIZE, input_size));
}

