VOID CT_Im_PRO_1_70_Print( const char* string, UCHAR ch, UCHAR paen_trg )
{
    if(IO_PRO.SEN.LVDS[ch].LVDSPAEN.bit.PAEN != paen_trg) Ddim_Print(( "Im_PRO_LVDS_Set_PAEN(%u) %s result:PAEN (%u) LVDSTRG(%u) paen_trg(%u)\n", ch, string, IO_PRO.SEN.LVDS[ch].LVDSPAEN.bit.PAEN, IO_PRO.SEN.LVDS[ch].LVDSTRG.bit.LVDSTRG, paen_trg ));
}                                                    

VOID CT_Im_PRO_1_70( const UINT32 idx )
{
    INT32               ercd;
    UCHAR               paen_trg;
    UCHAR               ch;

    if( idx == 1 ) {
//        Ddim_Print(( "Target register address\n" ));
//        Ddim_Print(( "Im_PRO_LVDS_Set_PAEN(0) LVDSPAEN  (0x%08lx, %lx)\n", (ULONG)&IO_PRO.SEN.LVDS[0].LVDSPAEN,    IO_PRO.SEN.LVDS[0].LVDSPAEN ));
//        Ddim_Print(( "Im_PRO_LVDS_Set_PAEN(1) LVDSPAEN  (0x%08lx, %lx)\n", (ULONG)&IO_PRO.SEN.LVDS[1].LVDSPAEN,    IO_PRO.SEN.LVDS[1].LVDSPAEN ));
//        Ddim_Print(( "Im_PRO_LVDS_Set_PAEN(2) LVDSPAEN  (0x%08lx, %lx)\n", (ULONG)&IO_PRO.SEN.LVDS[2].LVDSPAEN,    IO_PRO.SEN.LVDS[2].LVDSPAEN ));
//        Ddim_Print(( "Im_PRO_LVDS_Set_PAEN(3) LVDSPAEN  (0x%08lx, %lx)\n", (ULONG)&IO_PRO.SEN.LVDS[3].LVDSPAEN,    IO_PRO.SEN.LVDS[3].LVDSPAEN ));

        // enable value parameter
        ch = E_IM_PRO_LVDS_CH_3;
        paen_trg = 1;
        ercd = Im_PRO_LVDS_Set_PAEN( ch, paen_trg );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_LVDS_Set_PAEN() max_para Error ercd=0x%x\n", ercd ));
        }
        else {
            CT_Im_PRO_1_70_Print( "max_para", ch, paen_trg );
        }

        // disable value parameter
        ch = E_IM_PRO_LVDS_CH_0;
        paen_trg = 0;
        ercd = Im_PRO_LVDS_Set_PAEN( ch, paen_trg );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_LVDS_Set_PAEN() min_para Error ercd=0x%x\n", ercd ));
        }
        else {
            CT_Im_PRO_1_70_Print( "min_para", ch, paen_trg );
        }

        // macro running error test
        ch = E_IM_PRO_LVDS_CH_0;
        paen_trg = 0;
#ifdef CO_DEBUG_ON_PC
        IO_PRO.SEN.LVDS[ch].LVDSTRG.bit.LVDSTRG = D_IM_PRO_TRG_STATUS_RUNNING;
#else
        Im_PRO_LVDS_Start( ch );
#endif
        ercd = Im_PRO_LVDS_Set_PAEN( ch, paen_trg );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_LVDS_Set_PAEN() min_para Error ercd=0x%x\n", ercd ));
        }
        else {
            CT_Im_PRO_1_70_Print( "macro running error", ch, paen_trg );
        }
#ifdef CO_DEBUG_ON_PC
        IO_PRO.SEN.LVDS[ch].LVDSTRG.bit.LVDSTRG = D_IM_PRO_TRG_STATUS_STOPPED;
#else
        Im_PRO_LVDS_Stop( ch );
#endif
    }
}

