VOID CT_Im_PRO_2_1( const UINT32 idx )
{
    E_IM_PRO_UNIT_NUM unit_no;
    if( idx == 1 ) {
        for( unit_no = 0; unit_no < E_IM_PRO_UNIT_NUM_MAX; unit_no++ ) {
            Im_PRO_SROTOP_Init( unit_no );
            Ddim_Print(( "Im_PRO_SROTOP_Init(%u) result:SR(%u)\n", unit_no, IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SR.bit.SR ));
        }
    }
}

VOID CT_Im_PRO_2_2( const UINT32 idx )
{
    INT32 ercd;
    E_IM_PRO_UNIT_NUM unit_no;

    if( idx == 1 ) {
        for( unit_no = 0; unit_no < E_IM_PRO_UNIT_NUM_MAX; unit_no++ ) {
//            Ddim_Print(( "Target register address\n" ));
//            Ddim_Print(( "Im_PRO_SROTOP_SW_Reset(%u) SR (0x%08lx, %lx)\n", unit_no, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SR.word,   IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SR.word ));

            // Normal case
            ercd = Im_PRO_SROTOP_SW_Reset( unit_no );
            if( ercd != D_DDIM_USER_E_OK ) {
                Ddim_Print(( "Im_PRO_SROTOP_SW_Reset(%u) Error ercd=0x%x\n", unit_no, ercd ));
            }
            else {
                Ddim_Print(( "Im_PRO_SROTOP_SW_Reset(%u) result:SR(%u)\n", unit_no, IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SR.bit.SR ));
            }

            // illegal case
            Im_PRO_VRB_Start( unit_no );

            ercd = Im_PRO_SROTOP_SW_Reset( unit_no );
            if( ercd != D_DDIM_USER_E_OK ) {
                Ddim_Print(( "Im_PRO_SROTOP_SW_Reset(%u) Error ercd=0x%x\n", unit_no, ercd ));
            }
            else {
                Ddim_Print(( "Im_PRO_SROTOP_SW_Reset(%u) result:SR(%u)\n", unit_no, IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SR.bit.SR ));
            }
            Im_PRO_VRB_Stop( unit_no, 0 );
        }
    }
}

VOID CT_Im_PRO_2_3( const UINT32 idx )
{
    INT32 ercd;
    E_IM_PRO_UNIT_NUM unit_no;
    UCHAR clk_type;
    UCHAR on_off;
    UCHAR wait_skip;

    if( idx == 1 ) {
        for( unit_no = 0; unit_no < E_IM_PRO_UNIT_NUM_MAX; unit_no++ ) {
//            Ddim_Print(( "Target register address\n" ));
//            Ddim_Print(( "Im_PRO_SROTOP_Control_Clock(%lu) CLKSTP1 (0x%08lx, %lx)\n", unit_no, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.CLKSTP.word, IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.CLKSTP.word ));

            for( wait_skip = 0; wait_skip < 2; wait_skip++ ) {
                for( clk_type = E_IM_PRO_SROTOP_CLK_TYPE_SROCLK; clk_type < E_IM_PRO_SROTOP_CLK_TYPE_SROCLK2 + 1; clk_type++ ) {
                    // STATCLK ON
                    on_off      = D_IM_PRO_CLOCK_ON;
                    ercd = Im_PRO_SROTOP_Control_Clock( unit_no, clk_type, on_off, wait_skip );
                    if( ercd != D_DDIM_USER_E_OK ) {
                        Ddim_Print(( "Im_PRO_SROTOP_Control_Clock( %u, %u, %u, %u ) Error ercd=0x%x\n", unit_no, clk_type, on_off, wait_skip, ercd ));
                    }
                    else {
                        Ddim_Print(( "Im_PRO_SROTOP_Control_Clock( %u, %u, %u, %u ) result:CLKSTP1(%lu)\n", unit_no, clk_type, on_off, wait_skip, IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.CLKSTP.word ));
                    }

                    // STATCLK OFF
                    on_off      = D_IM_PRO_CLOCK_OFF;
                    ercd = Im_PRO_SROTOP_Control_Clock( unit_no, clk_type, on_off, wait_skip );
                    if( ercd != D_DDIM_USER_E_OK ) {
                        Ddim_Print(( "Im_PRO_SROTOP_Control_Clock( %u, %u, %u, %u ) Error ercd=0x%x\n", unit_no, clk_type, on_off, wait_skip, ercd ));
                    }
                    else {
                        Ddim_Print(( "Im_PRO_SROTOP_Control_Clock( %u, %u, %u, %u ) result:CLKSTP1(%lu)\n", unit_no, clk_type, on_off, wait_skip, IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.CLKSTP.word ));
                    }
                }
            }
        }
    }
}

VOID CT_Im_PRO_2_4_Print( const char* string, E_IM_PRO_UNIT_NUM unit_no, INT32 ercd, T_IM_PRO_SROTOP_CTRL* ctrl )
{
    if( ercd == D_DDIM_USER_E_OK ) {
        if(IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SROTOPCTL1.bit.SROISW != ctrl->input_mode          ) Ddim_Print(( "Im_PRO_STATTOP_Ctrl(%u) result:SROISW (%d) in(%d)\n", unit_no, IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SROTOPCTL1.bit.SROISW , ctrl->input_mode              ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SROTOPCTL1.bit.SROMD  != ctrl->sro_mode_sel        ) Ddim_Print(( "Im_PRO_STATTOP_Ctrl(%u) result:SROMD  (%d) in(%d)\n", unit_no, IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SROTOPCTL1.bit.SROMD  , ctrl->sro_mode_sel            ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SROTOPCTL1.bit.CAGSL  != ctrl->cag_target_sel      ) Ddim_Print(( "Im_PRO_STATTOP_Ctrl(%u) result:CAGSL  (%d) in(%d)\n", unit_no, IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SROTOPCTL1.bit.CAGSL  , ctrl->cag_target_sel          ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SROTOPCTL1.bit.BRPSW0 != ctrl->bay_out_path_sel    ) Ddim_Print(( "Im_PRO_STATTOP_Ctrl(%u) result:BRPSW0 (%d) in(%d)\n", unit_no, IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SROTOPCTL1.bit.BRPSW0 , ctrl->bay_out_path_sel        ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SROTOPCTL1.bit.BRPSW1 != ctrl->b2b_connect_path_sel) Ddim_Print(( "Im_PRO_STATTOP_Ctrl(%u) result:BRPSW1 (%d) in(%d)\n", unit_no, IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SROTOPCTL1.bit.BRPSW1 , ctrl->b2b_connect_path_sel    ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SROTOPCTL1.bit.BRPSW2 != ctrl->ltm_connect_path_sel) Ddim_Print(( "Im_PRO_STATTOP_Ctrl(%u) result:BRPSW2 (%d) in(%d)\n", unit_no, IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SROTOPCTL1.bit.BRPSW2 , ctrl->ltm_connect_path_sel    ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SROTOPCTL2.bit.ORG0   != ctrl->first_pixel[0]      ) Ddim_Print(( "Im_PRO_STATTOP_Ctrl(%u) result:ORG0   (%d) in(%d)\n", unit_no, IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SROTOPCTL2.bit.ORG0   , ctrl->first_pixel[0]          ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SROTOPCTL2.bit.ORG1   != ctrl->first_pixel[1]      ) Ddim_Print(( "Im_PRO_STATTOP_Ctrl(%u) result:ORG1   (%d) in(%d)\n", unit_no, IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.SROTOPCTL2.bit.ORG1   , ctrl->first_pixel[1]          ));
    }
    else {
        Ddim_Print(( "Im_PRO_STATTOP_Ctrl(%u) error ercd=0x%x\n", unit_no, ercd ));
    }
}

VOID CT_Im_PRO_2_4( const UINT32 idx )
{
    INT32 ercd;
    E_IM_PRO_UNIT_NUM unit_no;
    T_IM_PRO_SROTOP_CTRL    ctrl_max = {
        .input_mode             = E_IM_PRO_SROTOP_INPUT_MODE_REINPUT,
        .sro_mode_sel           = E_IM_PRO_SROTOP_MODE2,
        .cag_target_sel         = E_IM_PRO_SROTOP_CAG_TARGET_BLOCK_B2B,
        .bay_out_path_sel       = E_IM_PRO_SROTOP_PATH_SEL_BAY_OUT_CAG_OUT,
        .b2b_connect_path_sel   = E_IM_PRO_SROTOP_PATH_SEL_B2B_CONN_WITH_BR,
        .ltm_connect_path_sel   = E_IM_PRO_SROTOP_PATH_SEL_LTM_CONN_WITH_BR,
        .first_pixel[0]         = E_IM_PRO_ORG_GB,
        .first_pixel[1]         = E_IM_PRO_ORG_GB,
    };

    T_IM_PRO_SROTOP_CTRL    ctrl_min = {
        .input_mode             = E_IM_PRO_SROTOP_INPUT_MODE_DIRECT,
        .sro_mode_sel           = E_IM_PRO_SROTOP_MODE0,
        .cag_target_sel         = E_IM_PRO_SROTOP_CAG_TARGET_BLOCK_SRO,
        .bay_out_path_sel       = E_IM_PRO_SROTOP_PATH_SEL_BAY_OUT_WITHOUT_BR,
        .b2b_connect_path_sel   = E_IM_PRO_SROTOP_PATH_SEL_B2B_CONN_WITHOUT_BR,
        .ltm_connect_path_sel   = E_IM_PRO_SROTOP_PATH_SEL_LTM_CONN_WITHOUT_BR,
        .first_pixel[0]         = E_IM_PRO_ORG_R,
        .first_pixel[1]         = E_IM_PRO_ORG_R,
    };

    if( idx == 1 ) {
        for( unit_no = 0; unit_no < E_IM_PRO_UNIT_NUM_MAX; unit_no++ ) {
            ercd = Im_PRO_SROTOP_Ctrl( unit_no, &ctrl_max );
            CT_Im_PRO_2_4_Print( "max_para", unit_no, ercd, &ctrl_max );

            ercd = Im_PRO_SROTOP_Ctrl( unit_no, &ctrl_min );
            CT_Im_PRO_2_4_Print( "min_para", unit_no, ercd, &ctrl_min );
        }
    }
}

VOID CT_Im_PRO_2_5_Print( const char* string, E_IM_PRO_UNIT_NUM unit_no, UCHAR               ch, INT32 ercd, T_IM_PRO_SROTOP_WEITGEN_CTRL* ctrl )
{
    if( ercd == D_DDIM_USER_E_OK ) {
        if( ch == E_IM_PRO_WEITGEN_CH0 ) {
            if(IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.WAITGENV.bit.GENV0 != ctrl->v_wait_signal_pos) Ddim_Print(( "Im_PRO_SROTOP_WEITGEN_Ctrl(%u %u) result:GENV0    (%d) in(%d)\n", unit_no, ch, IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.WAITGENV.bit.GENV0    , ctrl->v_wait_signal_pos   ));
            if(IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.WAITGENH.bit.GENH0 != ctrl->h_wait_signal_pos) Ddim_Print(( "Im_PRO_SROTOP_WEITGEN_Ctrl(%u %u) result:GENH0    (%d) in(%d)\n", unit_no, ch, IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.WAITGENH.bit.GENH0    , ctrl->h_wait_signal_pos   ));
        }
        else {
            if(IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.WAITGENV.bit.GENV1 != ctrl->v_wait_signal_pos) Ddim_Print(( "Im_PRO_SROTOP_WEITGEN_Ctrl(%u %u) result:GENV0    (%d) in(%d)\n", unit_no, ch, IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.WAITGENV.bit.GENV1    , ctrl->v_wait_signal_pos   ));
            if(IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.WAITGENH.bit.GENH1 != ctrl->h_wait_signal_pos) Ddim_Print(( "Im_PRO_SROTOP_WEITGEN_Ctrl(%u %u) result:GENH0    (%d) in(%d)\n", unit_no, ch, IO_PRO.IMG_PIPE[unit_no].SRO.SROTOP.WAITGENH.bit.GENH1    , ctrl->h_wait_signal_pos   ));
        }
    }
    else {
        Ddim_Print(( "Im_PRO_SROTOP_WEITGEN_Ctrl(%u %u) error ercd=0x%x\n", unit_no, ch, ercd ));
    }
}

