VOID CT_Im_PRO_2_12_Print( const char* string, E_IM_PRO_UNIT_NUM unit_no, E_IM_PRO_FSHDL_CH ch, INT32 ercd, T_IM_PRO_FSHDL_COMMON_CTRL* fshdl_ctrl )
{
    const T_IM_PRO_SRO_FSHDL_INFO* fshdl_info;

    if( ercd == D_DDIM_USER_E_OK ) {
        im_pro_comm_get_fshdl_reg_info( unit_no, ch, &fshdl_info );
        if(fshdl_info->reg_ptr->FFSHCTL.bit.FFSHPTMD  != fshdl_ctrl->montage_mode) Ddim_Print(( "Im_PRO_FSHDL_Ctrl(%u %u) %s result:FSHDLH 0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHCTL.word  , fshdl_info->reg_ptr->FFSHCTL.bit.FFSHPTMD  ,fshdl_ctrl->montage_mode   ));
        if(fshdl_info->reg_ptr->FFSHUL1.bit.FFSHULRR  != fshdl_ctrl->clip_r      ) Ddim_Print(( "Im_PRO_FSHDL_Ctrl(%u %u) %s result:FSHDLH 0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHUL1.word  , fshdl_info->reg_ptr->FFSHUL1.bit.FFSHULRR  ,fshdl_ctrl->clip_r         ));
        if(fshdl_info->reg_ptr->FFSHUL1.bit.FFSHULGR  != fshdl_ctrl->clip_gr     ) Ddim_Print(( "Im_PRO_FSHDL_Ctrl(%u %u) %s result:FSHDLH 0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHUL1.word  , fshdl_info->reg_ptr->FFSHUL1.bit.FFSHULGR  ,fshdl_ctrl->clip_gr        ));
        if(fshdl_info->reg_ptr->FFSHUL2.bit.FFSHULGB  != fshdl_ctrl->clip_gb     ) Ddim_Print(( "Im_PRO_FSHDL_Ctrl(%u %u) %s result:FSHDLH 0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHUL2.word  , fshdl_info->reg_ptr->FFSHUL2.bit.FFSHULGB  ,fshdl_ctrl->clip_gb        ));
        if(fshdl_info->reg_ptr->FFSHUL2.bit.FFSHULBB  != fshdl_ctrl->clip_b      ) Ddim_Print(( "Im_PRO_FSHDL_Ctrl(%u %u) %s result:FSHDLH 0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHUL2.word  , fshdl_info->reg_ptr->FFSHUL2.bit.FFSHULBB  ,fshdl_ctrl->clip_b         ));
    }
    else {
        Ddim_Print(( "Im_PRO_FSHDL_Ctrl(%u %u) error ercd=0x%x\n", unit_no, ch, ercd ));
    }
}

