VOID CT_Im_PRO_2_16_Print( const char* string, E_IM_PRO_UNIT_NUM unit_no, E_IM_PRO_FSHDL_CH ch, INT32 ercd, T_IM_PRO_FSHDL_FRAME_CTRL* fshdl_ctrl )
{
    const T_IM_PRO_SRO_FSHDL_INFO* fshdl_info;

    if( ercd == D_DDIM_USER_E_OK ) {
        im_pro_comm_get_fshdl_reg_info( unit_no, ch, &fshdl_info );
        if(fshdl_info->reg_ptr->FFSHGFMT.bit.FFSHGFMT     != fshdl_ctrl->select_format         ) Ddim_Print(( "Im_PRO_FSHDL_Set_Frame(%u %u) %s result:FFSHGFMT      0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHGFMT.word     , fshdl_info->reg_ptr->FFSHGFMT.bit.FFSHGFMT     ,fshdl_ctrl->select_format              ));
        if(fshdl_info->reg_ptr->FFSHSUBPR.bit.FFSHSUBPRH  != fshdl_ctrl->frame_horizontal_size ) Ddim_Print(( "Im_PRO_FSHDL_Set_Frame(%u %u) %s result:FFSHSUBPRH    0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHSUBPR.word    , fshdl_info->reg_ptr->FFSHSUBPR.bit.FFSHSUBPRH  ,fshdl_ctrl->frame_horizontal_size      ));
        if(fshdl_info->reg_ptr->FFSHSUBPR.bit.FFSHSUBPRV  != fshdl_ctrl->frame_vertical_size   ) Ddim_Print(( "Im_PRO_FSHDL_Set_Frame(%u %u) %s result:FFSHSUBPRV    0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHSUBPR.word    , fshdl_info->reg_ptr->FFSHSUBPR.bit.FFSHSUBPRV  ,fshdl_ctrl->frame_vertical_size        ));
        if(fshdl_info->reg_ptr->FFSHSUBSP.bit.FFSHSUBSPH  != fshdl_ctrl->horizontal_pixel      ) Ddim_Print(( "Im_PRO_FSHDL_Set_Frame(%u %u) %s result:FFSHSUBSPH    0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHSUBSP.word    , fshdl_info->reg_ptr->FFSHSUBSP.bit.FFSHSUBSPH  ,fshdl_ctrl->horizontal_pixel           ));
        if(fshdl_info->reg_ptr->FFSHSUBSP.bit.FFSHSUBSPV  != fshdl_ctrl->vertical_pixel        ) Ddim_Print(( "Im_PRO_FSHDL_Set_Frame(%u %u) %s result:FFSHSUBSPV    0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHSUBSP.word    , fshdl_info->reg_ptr->FFSHSUBSP.bit.FFSHSUBSPV  ,fshdl_ctrl->vertical_pixel             ));
        if(fshdl_info->reg_ptr->FFSHSUBDR.bit.FFSHSUBDRM  != fshdl_ctrl->Inverse_base          ) Ddim_Print(( "Im_PRO_FSHDL_Set_Frame(%u %u) %s result:FFSHSUBDRM    0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHSUBDR.word    , fshdl_info->reg_ptr->FFSHSUBDR.bit.FFSHSUBDRM  ,fshdl_ctrl->Inverse_base               ));
        if(fshdl_info->reg_ptr->FFSHSUBDR.bit.FFSHSUBDRE  != fshdl_ctrl->Inverse_exponent      ) Ddim_Print(( "Im_PRO_FSHDL_Set_Frame(%u %u) %s result:FFSHSUBDRE    0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHSUBDR.word    , fshdl_info->reg_ptr->FFSHSUBDR.bit.FFSHSUBDRE  ,fshdl_ctrl->Inverse_exponent           ));
        if(fshdl_info->reg_ptr->FFSHSUBST.bit.FFSHSUBSTH  != fshdl_ctrl->start_pos_h           ) Ddim_Print(( "Im_PRO_FSHDL_Set_Frame(%u %u) %s result:FFSHSUBSTH    0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHSUBST.word    , fshdl_info->reg_ptr->FFSHSUBST.bit.FFSHSUBSTH  ,fshdl_ctrl->start_pos_h                ));
        if(fshdl_info->reg_ptr->FFSHSUBST.bit.FFSHSUBSTV  != fshdl_ctrl->start_pos_v           ) Ddim_Print(( "Im_PRO_FSHDL_Set_Frame(%u %u) %s result:FFSHSUBSTV    0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHSUBST.word    , fshdl_info->reg_ptr->FFSHSUBST.bit.FFSHSUBSTV  ,fshdl_ctrl->start_pos_v                ));
        if(fshdl_info->reg_ptr->FFSHHWPH.bit.FFSHHWPH     != fshdl_ctrl->montage_pos_h         ) Ddim_Print(( "Im_PRO_FSHDL_Set_Frame(%u %u) %s result:FFSHHWPH      0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHHWPH.word     , fshdl_info->reg_ptr->FFSHHWPH.bit.FFSHHWPH     ,fshdl_ctrl->montage_pos_h              ));
        if(fshdl_info->reg_ptr->FFSHCCTL.bit.FFSHCEN      != fshdl_ctrl->sat_correction_enabled) Ddim_Print(( "Im_PRO_FSHDL_Set_Frame(%u %u) %s result:FFSHCEN       0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHCCTL.word     , fshdl_info->reg_ptr->FFSHCCTL.bit.FFSHCEN      ,fshdl_ctrl->sat_correction_enabled     ));
        if(fshdl_info->reg_ptr->FFSHLP1.bit.FFSHLPRR      != fshdl_ctrl->sat_slope_gain[0]     ) Ddim_Print(( "Im_PRO_FSHDL_Set_Frame(%u %u) %s result:FFSHLPRR      0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHLP1.word      , fshdl_info->reg_ptr->FFSHLP1.bit.FFSHLPRR      ,fshdl_ctrl->sat_slope_gain[0]          ));
        if(fshdl_info->reg_ptr->FFSHLP1.bit.FFSHLPGR      != fshdl_ctrl->sat_slope_gain[1]     ) Ddim_Print(( "Im_PRO_FSHDL_Set_Frame(%u %u) %s result:FFSHLPGR      0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHLP1.word      , fshdl_info->reg_ptr->FFSHLP1.bit.FFSHLPGR      ,fshdl_ctrl->sat_slope_gain[1]          ));
        if(fshdl_info->reg_ptr->FFSHLP2.bit.FFSHLPGB      != fshdl_ctrl->sat_slope_gain[2]     ) Ddim_Print(( "Im_PRO_FSHDL_Set_Frame(%u %u) %s result:FFSHLPGB      0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHLP2.word      , fshdl_info->reg_ptr->FFSHLP2.bit.FFSHLPGB      ,fshdl_ctrl->sat_slope_gain[2]          ));
        if(fshdl_info->reg_ptr->FFSHLP2.bit.FFSHLPBB      != fshdl_ctrl->sat_slope_gain[3]     ) Ddim_Print(( "Im_PRO_FSHDL_Set_Frame(%u %u) %s result:FFSHLPBB      0x%08lx(%u) in(%u)\n", unit_no, ch, string, (ULONG)&fshdl_info->reg_ptr->FFSHLP2.word      , fshdl_info->reg_ptr->FFSHLP2.bit.FFSHLPBB      ,fshdl_ctrl->sat_slope_gain[3]          ));
    }
    else {
        Ddim_Print(( "Im_PRO_FSHDL_Set_Frame(%u %u) error ercd=0x%x\n", unit_no, ch, ercd ));
    }
}

