        if(IO_PRO.IMG_PIPE[unit_no].SRO.CAG.CAGMD.bit.CLPSEL     != cag_ctrl->clip_mode              ) Ddim_Print(( "Im_PRO_CAG_Ctrl_Glv_Diff(%u) %s result:CLPSEL     0x%08lx(%u) in(%u)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.CAG.CAGMD.word   , IO_PRO.IMG_PIPE[unit_no].SRO.CAG.CAGMD.bit.CLPSEL     ,cag_ctrl->clip_mode                ));
