VOID CT_Im_PRO_2_26_Print( E_IM_PRO_UNIT_NUM unit_no )
{
    Ddim_Print(( "Im_PRO_DPC_Start(%u) result:DPCTRG 0x%08lx(%u)\n", unit_no, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCTRG.word, IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCTRG.bit.DPCTRG ));
}

VOID CT_Im_PRO_2_26( const UINT32 idx )
{
    E_IM_PRO_UNIT_NUM   unit_no;

    if( idx == 1 ) {
        for( unit_no = 0; unit_no < E_IM_PRO_UNIT_NUM_MAX; unit_no++ ) {
            Im_PRO_DPC_Start( unit_no );
            CT_Im_PRO_2_26_Print( unit_no );
        }
    }
}

VOID CT_Im_PRO_2_27_Print( E_IM_PRO_UNIT_NUM unit_no, UCHAR force )
{
    Ddim_Print(( "Im_PRO_DPC_Stop(%u %u) result:DPCTRG  0x%08lx(%u)\n", unit_no, force, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCTRG.word, IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCTRG.bit.DPCTRG ));
}

VOID CT_Im_PRO_2_27( const UINT32 idx )
{
    E_IM_PRO_UNIT_NUM   unit_no;
    UCHAR               force;

    if( idx == 1 ) {
        for( unit_no = 0; unit_no < E_IM_PRO_UNIT_NUM_MAX; unit_no++ ) {
            for( force = 0; force < 2 + 1; force++ ) {
#ifdef CO_DEBUG_ON_PC
                IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCTRG.bit.DPCTRG = 3;
#endif
                Im_PRO_DPC_Stop( unit_no, force );
                CT_Im_PRO_2_27_Print( unit_no, force );
            }
        }
    }
}

VOID CT_Im_PRO_2_28_Print( const char* string, E_IM_PRO_UNIT_NUM unit_no, INT32 ercd, T_IM_PRO_DPC_CTRL* dpc_ctrl )
{
    if( ercd == D_DDIM_USER_E_OK ) {
        if(IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCMD.bit.DPCMD  != dpc_ctrl->dpc_mode   ) Ddim_Print(( "Im_PRO_DPC_Ctrl(%u) %s result:DPCMD   0x%08lx(%u) in(%u)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCMD.word   , IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCMD.bit.DPCMD  ,dpc_ctrl->dpc_mode     ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCMD.bit.DPCRTZ != dpc_ctrl->thre_conv_0) Ddim_Print(( "Im_PRO_DPC_Ctrl(%u) %s result:DPCRTZ  0x%08lx(%u) in(%u)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCMD.word   , IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCMD.bit.DPCRTZ ,dpc_ctrl->thre_conv_0  ));
    }
    else {
        Ddim_Print(( "Im_PRO_DPC_Ctrl(%u) error ercd=0x%x\n", unit_no, ercd ));
    }
}

