    if( ercd == D_DDIM_USER_E_OK ) {
        if(IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCGWP.bit.DPCGH     != dpc_ctrl->g_pos_x) Ddim_Print(( "Im_PRO_DPC_Set_Area(%u) %s result:DPCGH   0x%08lx(%u) in(%u)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCGWP.word  , IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCGWP.bit.DPCGH     ,dpc_ctrl->g_pos_x  ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCGWP.bit.DPCGV     != dpc_ctrl->g_pos_y) Ddim_Print(( "Im_PRO_DPC_Set_Area(%u) %s result:DPCGV   0x%08lx(%u) in(%u)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCGWP.word  , IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCGWP.bit.DPCGV     ,dpc_ctrl->g_pos_y  ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCGWS.bit.DPCGHW    != dpc_ctrl->g_width) Ddim_Print(( "Im_PRO_DPC_Set_Area(%u) %s result:DPCGHW  0x%08lx(%u) in(%u)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCGWS.word  , IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCGWS.bit.DPCGHW    ,dpc_ctrl->g_width  ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCGWS.bit.DPCGVW    != dpc_ctrl->g_lines) Ddim_Print(( "Im_PRO_DPC_Set_Area(%u) %s result:DPCGVW  0x%08lx(%u) in(%u)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCGWS.word  , IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCGWS.bit.DPCGVW    ,dpc_ctrl->g_lines  ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCWP.bit.DPCH       != dpc_ctrl->pos_x  ) Ddim_Print(( "Im_PRO_DPC_Set_Area(%u) %s result:DPCH    0x%08lx(%u) in(%u)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCWP.word   , IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCWP.bit.DPCH       ,dpc_ctrl->pos_x    ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCWP.bit.DPCV       != dpc_ctrl->pos_y  ) Ddim_Print(( "Im_PRO_DPC_Set_Area(%u) %s result:DPCV    0x%08lx(%u) in(%u)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCWP.word   , IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCWP.bit.DPCV       ,dpc_ctrl->pos_y    ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCWS.bit.DPCHW      != dpc_ctrl->width  ) Ddim_Print(( "Im_PRO_DPC_Set_Area(%u) %s result:DPCHW   0x%08lx(%u) in(%u)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCWS.word   , IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCWS.bit.DPCHW      ,dpc_ctrl->width    ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCWS.bit.DPCVW      != dpc_ctrl->lines  ) Ddim_Print(( "Im_PRO_DPC_Set_Area(%u) %s result:DPCVW   0x%08lx(%u) in(%u)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCWS.word   , IO_PRO.IMG_PIPE[unit_no].SRO.DPC.DPCWS.bit.DPCVW      ,dpc_ctrl->lines    ));
    }
    else {
        Ddim_Print(( "Im_PRO_DPC_Set_Area(%u) error ercd=0x%x\n", unit_no, ercd ));
    }
