VOID CT_Im_PRO_2_37( const UINT32 idx )
{
    INT32 ercd;
    E_IM_PRO_UNIT_NUM   unit_no;
    const T_IM_PRO_RDMA_DPC_ADDR*   dpc_ctrl;

    if( idx == 1 ) {
        for( unit_no = 0; unit_no < E_IM_PRO_UNIT_NUM_MAX; unit_no++ ) {
            ercd = Im_PRO_Get_RdmaAddr_DPC_Cntl( unit_no, &dpc_ctrl );
            if( ercd != D_DDIM_USER_E_OK ) {
                Ddim_Print(( "Im_PRO_Get_RdmaAddr_DPC_Cntl(%u) max_para Error ercd=0x%x\n", unit_no, ercd ));
            }
            else {
                CT_Im_PRO_2_37_Print( "", unit_no, ercd, &dpc_ctrl );
            }
        }
    }
}

VOID CT_Im_PRO_2_38_Print( E_IM_PRO_UNIT_NUM unit_no )
{
    Ddim_Print(( "Im_PRO_FFC_Start(%u) result:FCTRG  0x%08lx(%u)\n", unit_no, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.FFC.FCTRG.word, IO_PRO.IMG_PIPE[unit_no].SRO.FFC.FCTRG.bit.FCTRG ));
}

VOID CT_Im_PRO_2_38( const UINT32 idx )
{
    E_IM_PRO_UNIT_NUM   unit_no;

    if( idx == 1 ) {
        for( unit_no = 0; unit_no < E_IM_PRO_UNIT_NUM_MAX; unit_no++ ) {
            Im_PRO_FFC_Start( unit_no );
            CT_Im_PRO_2_38_Print( unit_no );
        }
    }
}

VOID CT_Im_PRO_2_39_Print( E_IM_PRO_UNIT_NUM unit_no, UCHAR force )
{
    Ddim_Print(( "Im_PRO_FFC_Stop(%u %u) result:FCTRG   0x%08lx(%u)\n", unit_no, force, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.FFC.FCTRG.word, IO_PRO.IMG_PIPE[unit_no].SRO.FFC.FCTRG.bit.FCTRG ));
}

VOID CT_Im_PRO_2_39( const UINT32 idx )
{
    E_IM_PRO_UNIT_NUM   unit_no;
    UCHAR               force;

    if( idx == 1 ) {
        for( unit_no = 0; unit_no < E_IM_PRO_UNIT_NUM_MAX; unit_no++ ) {
            for( force = 0; force < 2 + 1; force++ ) {
#ifdef CO_DEBUG_ON_PC
                IO_PRO.IMG_PIPE[unit_no].SRO.FFC.FCTRG.bit.FCTRG = 3;
#endif
                Im_PRO_FFC_Stop( unit_no, force );
                CT_Im_PRO_2_39_Print( unit_no, force );
            }
        }
    }
}

