VOID CT_Im_PRO_2_56_Print( const char* string, E_IM_PRO_UNIT_NUM unit_no, E_IM_PRO_FFSH_CH ch, INT32 ercd, T_IM_PRO_FFSH_CTRL* ffsh_ctrl )
{
    if( ercd == D_DDIM_USER_E_OK ) {
        if(IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBPR.bit.FFSHSUBPRH != ffsh_ctrl->h_size_correction_coeff        ) Ddim_Print(( "Im_PRO_FFSH_Ctrl(%u %u) %s result:FFSHSUBPRH  0x%08lx(%d) in(%d)\n", unit_no, ch, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBPR.word  , IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBPR.bit.FFSHSUBPRH    ,ffsh_ctrl->h_size_correction_coeff         ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBPR.bit.FFSHSUBPRV != ffsh_ctrl->v_size_correction_coeff        ) Ddim_Print(( "Im_PRO_FFSH_Ctrl(%u %u) %s result:FFSHSUBPRV  0x%08lx(%d) in(%d)\n", unit_no, ch, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBPR.word  , IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBPR.bit.FFSHSUBPRV    ,ffsh_ctrl->v_size_correction_coeff         ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBSP.bit.FFSHSUBSPH != ffsh_ctrl->h_pixel_unit_interpolation     ) Ddim_Print(( "Im_PRO_FFSH_Ctrl(%u %u) %s result:FFSHSUBSPH  0x%08lx(%d) in(%d)\n", unit_no, ch, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBSP.word  , IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBSP.bit.FFSHSUBSPH    ,ffsh_ctrl->h_pixel_unit_interpolation      ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBSP.bit.FFSHSUBSPV != ffsh_ctrl->v_pixel_unit_interpolation     ) Ddim_Print(( "Im_PRO_FFSH_Ctrl(%u %u) %s result:FFSHSUBSPV  0x%08lx(%d) in(%d)\n", unit_no, ch, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBSP.word  , IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBSP.bit.FFSHSUBSPV    ,ffsh_ctrl->v_pixel_unit_interpolation      ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBDR.bit.FFSHSUBDRM != ffsh_ctrl->rad_inverse_coeff_interpolation) Ddim_Print(( "Im_PRO_FFSH_Ctrl(%u %u) %s result:FFSHSUBDRM  0x%08lx(%d) in(%d)\n", unit_no, ch, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBDR.word  , IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBDR.bit.FFSHSUBDRM    ,ffsh_ctrl->rad_inverse_coeff_interpolation ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBDR.bit.FFSHSUBDRE != ffsh_ctrl->exp_inverse_coeff_interpolation) Ddim_Print(( "Im_PRO_FFSH_Ctrl(%u %u) %s result:FFSHSUBDRE  0x%08lx(%d) in(%d)\n", unit_no, ch, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBDR.word  , IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBDR.bit.FFSHSUBDRE    ,ffsh_ctrl->exp_inverse_coeff_interpolation ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBST.bit.FFSHSUBSTH != ffsh_ctrl->h_start_pos_coeff              ) Ddim_Print(( "Im_PRO_FFSH_Ctrl(%u %u) %s result:FFSHSUBSTH  0x%08lx(%d) in(%d)\n", unit_no, ch, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBST.word  , IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBST.bit.FFSHSUBSTH    ,ffsh_ctrl->h_start_pos_coeff               ));
        if(IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBST.bit.FFSHSUBSTV != ffsh_ctrl->v_start_pos_coeff              ) Ddim_Print(( "Im_PRO_FFSH_Ctrl(%u %u) %s result:FFSHSUBSTV  0x%08lx(%d) in(%d)\n", unit_no, ch, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBST.word  , IO_PRO.IMG_PIPE[unit_no].SRO.FFSH[ch].FFSHSUBST.bit.FFSHSUBSTV    ,ffsh_ctrl->v_start_pos_coeff               ));
    }
    else {
        Ddim_Print(( "Im_PRO_FFSH_Ctrl(%u %u) error ercd=0x%x\n", unit_no, ch, ercd ));
    }
}

