VOID CT_Im_PRO_2_74( const UINT32 idx )
{
    INT32 ercd;
    E_IM_PRO_UNIT_NUM               unit_no;
    UCHAR                           ch;
    const T_IM_PRO_RDMA_SDC_ADDR*   sdc_ctrl;

    if( idx == 1 ) {
        for( unit_no = 0; unit_no < E_IM_PRO_UNIT_NUM_MAX; unit_no++ ) {
            for( ch = E_IM_PRO_SDC_CH0; ch < E_IM_PRO_SDC_CH1 + 1; ch++ ) {
                ercd = Im_PRO_Get_RdmaAddr_SDC_Cntl( unit_no, ch, &sdc_ctrl );
                if( ercd != D_DDIM_USER_E_OK ) {
                    Ddim_Print(( "Im_PRO_Get_RdmaAddr_SDC_Cntl(%u %u) max_para Error ercd=0x%x\n", unit_no, ch, ercd ));
                }
                else {
                    CT_Im_PRO_2_74_Print( "", unit_no, ch, ercd, &sdc_ctrl );
                }
            }
        }
    }
}

VOID CT_Im_PRO_2_75_Print( const char* string, E_IM_PRO_UNIT_NUM unit_no, E_IM_PRO_SDC_CH ch, E_IM_PRO_SDC_GAIN_TABLE_SEL tbl_sel, INT32 ercd, const T_IM_PRO_RDMA_SDC_GAIN_TBL_ADDR** sdc_ctrl )
{
    const T_IM_PRO_SRO_SDC_INFO* sdc_info;

    if( ercd == D_DDIM_USER_E_OK ) {
        im_pro_comm_get_sdc_reg_info( unit_no, ch, &sdc_info );
        Ddim_Print(( "Im_PRO_Get_RdmaAddr_SDC_Gain_Tbl(%u %u %u) %s result:SDCGD    0x%08lx reg_addr (0x%08lx)\n", unit_no, ch, tbl_sel, string, (ULONG)&sdc_info->tbl_reg_ptr[tbl_sel].hword   ,(ULONG)(*sdc_ctrl)->SDCGD ));
    }
    else {
        Ddim_Print(( "Im_PRO_Get_RdmaAddr_SDC_Gain_Tbl(%u %u %u) error ercd=0x%x\n", unit_no, ch, tbl_sel, ercd ));
    }
}

VOID CT_Im_PRO_2_75( const UINT32 idx )
{
    INT32 ercd;
    E_IM_PRO_UNIT_NUM           unit_no;
    UCHAR                       ch;
    UCHAR                       tbl_sel;
    const T_IM_PRO_RDMA_SDC_GAIN_TBL_ADDR*  sdc_ctrl;

    if( idx == 1 ) {
        for( unit_no = 0; unit_no < E_IM_PRO_UNIT_NUM_MAX; unit_no++ ) {
            for( ch = E_IM_PRO_SDC_CH0; ch < E_IM_PRO_SDC_CH1 + 1; ch++ ) {
                for( tbl_sel = E_IM_PRO_SDC_GAIN_TABLE_SEL_0; tbl_sel < E_IM_PRO_SDC_GAIN_TABLE_SEL_1 + 1; tbl_sel++ ) {
                    ercd = Im_PRO_Get_RdmaAddr_SDC_Gain_Tbl( unit_no, ch, tbl_sel, &sdc_ctrl );
                    if( ercd != D_DDIM_USER_E_OK ) {
                        Ddim_Print(( "Im_PRO_Get_RdmaAddr_SDC_Gain_Tbl(%u %u %u) max_para Error ercd=0x%x\n", unit_no, ch, tbl_sel, ercd ));
                    }
                    else {
                        CT_Im_PRO_2_75_Print( "", unit_no, ch, tbl_sel, ercd, &sdc_ctrl );
                    }
                }
            }
        }
    }
}

