{
    E_IM_PRO_UNIT_NUM unit_no;
    if( idx == 1 ) {
        for( unit_no = 0; unit_no < E_IM_PRO_UNIT_NUM_MAX; unit_no++ ) {
            Im_PRO_B2BTOP_Init( unit_no );
            Ddim_Print(( "Im_PRO_B2BTOP_Init(%u) result:SR(%u)\n", unit_no, IO_PRO.IMG_PIPE[unit_no].B2B.B2BTOP.SR.bit.SR ));
        }
    }
}

