        if(IO_PRO.IMG_PIPE[unit_no].B2B.ELF.ELFGWP.bit.ELFGH  != elf_ctrl->g_pos_x) Ddim_Print(( "Im_PRO_ELF_Set_Area(%u) %s result:ELFGH   0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.ELF.ELFGWP.word  , IO_PRO.IMG_PIPE[unit_no].B2B.ELF.ELFGWP.bit.ELFGH     ,elf_ctrl->g_pos_x  ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.ELF.ELFGWP.bit.ELFGV  != elf_ctrl->g_pos_y) Ddim_Print(( "Im_PRO_ELF_Set_Area(%u) %s result:ELFGV   0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.ELF.ELFGWP.word  , IO_PRO.IMG_PIPE[unit_no].B2B.ELF.ELFGWP.bit.ELFGV     ,elf_ctrl->g_pos_y  ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.ELF.ELFWS.bit.ELFHW   != elf_ctrl->width  ) Ddim_Print(( "Im_PRO_ELF_Set_Area(%u) %s result:ELFHW   0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.ELF.ELFWS.word   , IO_PRO.IMG_PIPE[unit_no].B2B.ELF.ELFWS.bit.ELFHW      ,elf_ctrl->width    ));
