        if(IO_PRO.IMG_PIPE[unit_no].B2B.ELF.ELFWP.bit.ELFH    != elf_ctrl->pos_x  ) Ddim_Print(( "Im_PRO_ELF_Set_Area(%u) %s result:ELFH    0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.ELF.ELFWP.word   , IO_PRO.IMG_PIPE[unit_no].B2B.ELF.ELFWP.bit.ELFH       ,elf_ctrl->pos_x    ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.ELF.ELFWP.bit.ELFV    != elf_ctrl->pos_y  ) Ddim_Print(( "Im_PRO_ELF_Set_Area(%u) %s result:ELFV    0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.ELF.ELFWP.word   , IO_PRO.IMG_PIPE[unit_no].B2B.ELF.ELFWP.bit.ELFV       ,elf_ctrl->pos_y    ));
