        if(IO_PRO.IMG_PIPE[unit_no].B2B.ELF.LFTH.bit.LFTH         != elf_ctrl->l_threshold   ) Ddim_Print(( "Im_PRO_ELF_Set_E_L_Filter(%u) %s result:LFTH      0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.ELF.LFTH.word        , IO_PRO.IMG_PIPE[unit_no].B2B.ELF.LFTH.bit.LFTH            ,elf_ctrl->l_threshold      ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.ELF.ELCOME.bit.ELCOME1    != elf_ctrl->l_contour_1   ) Ddim_Print(( "Im_PRO_ELF_Set_E_L_Filter(%u) %s result:ELCOME1   0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.ELF.ELCOME.word      , IO_PRO.IMG_PIPE[unit_no].B2B.ELF.ELCOME.bit.ELCOME1       ,elf_ctrl->l_contour_1      ));
