VOID CT_Im_PRO_3_15( const UINT32 idx )
{
    INT32 ercd;
    E_IM_PRO_UNIT_NUM   unit_no;
    T_IM_PRO_ELF_1s5_SAMPLING   elf_ctrl_max = {
        .s1s5_threshold[0]      = 4095,
        .s1s5_threshold[1]      = 4095,
        .s1s5_threshold[2]      = 4095,
        .s1s5_nr_l1_E13[0]      = 256,
        .s1s5_nr_l1_E13[1]      = 256,
        .s1s5_nr_l1_E13[2]      = 256,
        .s1s5_nr_l2_E13[0]      = 256,
        .s1s5_nr_l2_E13[1]      = 256,
        .s1s5_nr_l2_E13[2]      = 256,
        .s1s5_nr_l3_E13[0]      = 256,
        .s1s5_nr_l3_E13[1]      = 256,
        .s1s5_nr_l3_E13[2]      = 256,
        .s1s5_nr_l4_E13[0]      = 256,
        .s1s5_nr_l4_E13[1]      = 256,
        .s1s5_nr_l4_E13[2]      = 256,
        .s1s5_nr_adjustment[0]  = 256,
        .s1s5_nr_adjustment[1]  = 256,
        .s1s5_nr_adjustment[2]  = 256,
        .s1s5_noise_limit_plus  = 4095,
        .s1s5_noise_limit_minus = 4095,
    };

    T_IM_PRO_ELF_1s5_SAMPLING   elf_ctrl_min = {
        .s1s5_threshold[0]      = 0,
        .s1s5_threshold[1]      = 0,
        .s1s5_threshold[2]      = 0,
        .s1s5_nr_l1_E13[0]      = 0,
        .s1s5_nr_l1_E13[1]      = 0,
        .s1s5_nr_l1_E13[2]      = 0,
        .s1s5_nr_l2_E13[0]      = 0,
        .s1s5_nr_l2_E13[1]      = 0,
        .s1s5_nr_l2_E13[2]      = 0,
        .s1s5_nr_l3_E13[0]      = 0,
        .s1s5_nr_l3_E13[1]      = 0,
        .s1s5_nr_l3_E13[2]      = 0,
        .s1s5_nr_l4_E13[0]      = 0,
        .s1s5_nr_l4_E13[1]      = 0,
        .s1s5_nr_l4_E13[2]      = 0,
        .s1s5_nr_adjustment[0]  = 0,
        .s1s5_nr_adjustment[1]  = 0,
        .s1s5_nr_adjustment[2]  = 0,
        .s1s5_noise_limit_plus  = 0,
        .s1s5_noise_limit_minus = 0,
    };

    if( idx == 1 ) {
        for( unit_no = 0; unit_no < E_IM_PRO_UNIT_NUM_MAX; unit_no++ ) {
            ercd = Im_PRO_ELF_Set_1s5_Sampling( unit_no, &elf_ctrl_max );
            if( ercd != D_DDIM_USER_E_OK ) {
                Ddim_Print(( "Im_PRO_ELF_Set_1s5_Sampling(%u) max_para Error ercd=0x%x\n", unit_no, ercd ));
            }
            else {
                CT_Im_PRO_3_15_Print( "max_para", unit_no, ercd, &elf_ctrl_max );
            }

            ercd = Im_PRO_ELF_Set_1s5_Sampling( unit_no, &elf_ctrl_min );
            if( ercd != D_DDIM_USER_E_OK ) {
                Ddim_Print(( "Im_PRO_ELF_Set_1s5_Sampling(%u) min_para Error ercd=0x%x\n", unit_no, ercd ));
            }
            else {
                CT_Im_PRO_3_15_Print( "min_para", unit_no, ercd, &elf_ctrl_min );
            }
        }
    }
}

