VOID CT_Im_PRO_3_27_Print( E_IM_PRO_UNIT_NUM unit_no, UCHAR force )
{
    Ddim_Print(( "Im_PRO_FSHD_Stop(%u %u) result:FSHDTRG    0x%08lx(%u)\n", unit_no, force, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSHDTRG.word, IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSHDTRG.bit.FSHDTRG ));
}

VOID CT_Im_PRO_3_27( const UINT32 idx )
{
    E_IM_PRO_UNIT_NUM   unit_no;
    UCHAR               force;

    if( idx == 1 ) {
        for( unit_no = 0; unit_no < E_IM_PRO_UNIT_NUM_MAX; unit_no++ ) {
            for( force = 0; force < 2 + 1; force++ ) {
#ifdef CO_DEBUG_ON_PC
                IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSHDTRG.bit.FSHDTRG = 3;
#endif
                Im_PRO_FSHD_Stop( unit_no, force );
                CT_Im_PRO_3_27_Print( unit_no, force );
            }
        }
    }
}

VOID CT_Im_PRO_3_28_Print( const char* string, E_IM_PRO_UNIT_NUM unit_no, INT32 ercd, T_IM_PRO_FSHD_COMMON_CTRL* fshd_ctrl )
{
    if( ercd == D_DDIM_USER_E_OK ) {
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSHDCTL.bit.FSMODE   != fshd_ctrl->correction_mode    ) Ddim_Print(( "Im_PRO_FSHD_Ctrl(%u) %s result:FSMODE     0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSHDCTL.word    , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSHDCTL.bit.FSMODE      ,fshd_ctrl->correction_mode     ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSHDCTL.bit.FWMODE   != fshd_ctrl->correction_mode_awb) Ddim_Print(( "Im_PRO_FSHD_Ctrl(%u) %s result:FWMODE     0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSHDCTL.word    , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSHDCTL.bit.FWMODE      ,fshd_ctrl->correction_mode_awb ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSHDCTL.bit.FSHDPTMD != fshd_ctrl->montage_mode       ) Ddim_Print(( "Im_PRO_FSHD_Ctrl(%u) %s result:FSHDPTMD   0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSHDCTL.word    , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSHDCTL.bit.FSHDPTMD    ,fshd_ctrl->montage_mode        ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSUL1.bit.FSULRR     != fshd_ctrl->clip_r             ) Ddim_Print(( "Im_PRO_FSHD_Ctrl(%u) %s result:FSULRR     0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSUL1.word      , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSUL1.bit.FSULRR        ,fshd_ctrl->clip_r              ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSUL1.bit.FSULGR     != fshd_ctrl->clip_gr            ) Ddim_Print(( "Im_PRO_FSHD_Ctrl(%u) %s result:FSULGR     0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSUL1.word      , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSUL1.bit.FSULGR        ,fshd_ctrl->clip_gr             ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSUL2.bit.FSULGB     != fshd_ctrl->clip_gb            ) Ddim_Print(( "Im_PRO_FSHD_Ctrl(%u) %s result:FSULGB     0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSUL2.word      , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSUL2.bit.FSULGB        ,fshd_ctrl->clip_gb             ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSUL2.bit.FSULBB     != fshd_ctrl->clip_b             ) Ddim_Print(( "Im_PRO_FSHD_Ctrl(%u) %s result:FSULBB     0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSUL2.word      , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSUL2.bit.FSULBB        ,fshd_ctrl->clip_b              ));
    }
    else {
        Ddim_Print(( "Im_PRO_FSHD_Ctrl(%u) error ercd=0x%x\n", unit_no, ercd ));
    }
}

