        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSUBPR.bit.FSSUBPRV  != fshd_ctrl->frame_vertical_size   ) Ddim_Print(( "Im_PRO_FSHD_Set_Frame(%u) %s result:FSSUBPRV  0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSUBPR.word    , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSUBPR.bit.FSSUBPRV    ,fshd_ctrl->frame_vertical_size     ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSUBSP.bit.FSSUBSPH  != fshd_ctrl->horizontal_pixel      ) Ddim_Print(( "Im_PRO_FSHD_Set_Frame(%u) %s result:FSSUBSPH  0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSUBSP.word    , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSUBSP.bit.FSSUBSPH    ,fshd_ctrl->horizontal_pixel        ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSUBSP.bit.FSSUBSPV  != fshd_ctrl->vertical_pixel        ) Ddim_Print(( "Im_PRO_FSHD_Set_Frame(%u) %s result:FSSUBSPV  0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSUBSP.word    , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSUBSP.bit.FSSUBSPV    ,fshd_ctrl->vertical_pixel          ));
