        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSUBDR.bit.FSSUBDRE  != fshd_ctrl->Inverse_exponent      ) Ddim_Print(( "Im_PRO_FSHD_Set_Frame(%u) %s result:FSSUBDRE  0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSUBDR.word    , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSUBDR.bit.FSSUBDRE    ,fshd_ctrl->Inverse_exponent        ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSHDHWPH.bit.FSHDHWPH != fshd_ctrl->montage_pos_h         ) Ddim_Print(( "Im_PRO_FSHD_Set_Frame(%u) %s result:FSHDHWPH  0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSHDHWPH.word   , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSHDHWPH.bit.FSHDHWPH   ,fshd_ctrl->montage_pos_h           ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSUBST.bit.FSSUBSTH  != fshd_ctrl->start_pos_h           ) Ddim_Print(( "Im_PRO_FSHD_Set_Frame(%u) %s result:FSSUBSTH  0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSUBST.word    , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSUBST.bit.FSSUBSTH    ,fshd_ctrl->start_pos_h             ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSUBST.bit.FSSUBSTV  != fshd_ctrl->start_pos_v           ) Ddim_Print(( "Im_PRO_FSHD_Set_Frame(%u) %s result:FSSUBSTV  0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSUBST.word    , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSUBST.bit.FSSUBSTV    ,fshd_ctrl->start_pos_v             ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSA1.bit.FSARR        != fshd_ctrl->magnification_r       ) Ddim_Print(( "Im_PRO_FSHD_Set_Frame(%u) %s result:FSARR     0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSA1.word       , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSA1.bit.FSARR          ,fshd_ctrl->magnification_r         ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSA1.bit.FSAGR        != fshd_ctrl->magnification_gr      ) Ddim_Print(( "Im_PRO_FSHD_Set_Frame(%u) %s result:FSAGR     0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSA1.word       , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSA1.bit.FSAGR          ,fshd_ctrl->magnification_gr        ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSA2.bit.FSAGB        != fshd_ctrl->magnification_gb      ) Ddim_Print(( "Im_PRO_FSHD_Set_Frame(%u) %s result:FSAGB     0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSA2.word       , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSA2.bit.FSAGB          ,fshd_ctrl->magnification_gb        ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSA2.bit.FSABB        != fshd_ctrl->magnification_b       ) Ddim_Print(( "Im_PRO_FSHD_Set_Frame(%u) %s result:FSABB     0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSA2.word       , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSA2.bit.FSABB          ,fshd_ctrl->magnification_b         ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSHDHCCTL.bit.FSHCEN  != fshd_ctrl->sat_correction_enabled) Ddim_Print(( "Im_PRO_FSHD_Set_Frame(%u) %s result:FSHCEN    0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSHDHCCTL.word  , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSHDHCCTL.bit.FSHCEN    ,fshd_ctrl->sat_correction_enabled  ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSLP1.bit.FSSLPRR    != fshd_ctrl->sat_slope_gain[0]     ) Ddim_Print(( "Im_PRO_FSHD_Set_Frame(%u) %s result:FSSLPRR   0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSLP1.word     , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSLP1.bit.FSSLPRR      ,fshd_ctrl->sat_slope_gain[0]       ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSLP1.bit.FSSLPGR    != fshd_ctrl->sat_slope_gain[1]     ) Ddim_Print(( "Im_PRO_FSHD_Set_Frame(%u) %s result:FSSLPGR   0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSLP1.word     , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSLP1.bit.FSSLPGR      ,fshd_ctrl->sat_slope_gain[1]       ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSLP2.bit.FSSLPGB    != fshd_ctrl->sat_slope_gain[2]     ) Ddim_Print(( "Im_PRO_FSHD_Set_Frame(%u) %s result:FSSLPGB   0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSLP2.word     , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSLP2.bit.FSSLPGB      ,fshd_ctrl->sat_slope_gain[2]       ));
        if(IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSLP2.bit.FSSLPBB    != fshd_ctrl->sat_slope_gain[3]     ) Ddim_Print(( "Im_PRO_FSHD_Set_Frame(%u) %s result:FSSLPBB   0x%08lx(%d) in(%d)\n", unit_no, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSLP2.word     , IO_PRO.IMG_PIPE[unit_no].B2B.FSHD.FSSLP2.bit.FSSLPBB      ,fshd_ctrl->sat_slope_gain[3]       ));
