VOID CT_Im_PRO_4_30( const UINT32 idx )
{
    INT32 ercd;
    UCHAR           ch;
    T_IM_PRO_AF_VERTICAL_CTRL   af_ctrl_max = {
        .update_cycle   = 15,
        .eval_cal_unit  = E_IM_PRO_AF_EVAL_CALC_UNIT_2,
        .start_addr     = D_IM_PRO_AF_AFVSH_MAX,
        .horizon_size   = D_IM_PRO_AF_AFVSHW_MAX,
        .iir_k          = 32767,
        .iir_a0         = 255,
        .iir_a1         = 255,
        .iir_a2         = 255,
        .iir_b1         = 32767,
        .iir_b2         = 32767,
        .cor_threshold  = 0x0FFF,
        .cor_level      = 0x0FFF,
        .fir_filter[0]  = 255,
        .fir_filter[1]  = 255,
        .fir_filter[2]  = 255,
    };

    T_IM_PRO_AF_VERTICAL_CTRL   af_ctrl_min = {
        .update_cycle   = 0,
        .eval_cal_unit  = E_IM_PRO_AF_EVAL_CALC_UNIT_0,
        .start_addr     = D_IM_PRO_AF_AFVSH_MIN,
        .horizon_size   = D_IM_PRO_AF_AFVSHW_MIN,
        .iir_k          = 0,
        .iir_a0         = 0,
        .iir_a1         = 0,
        .iir_a2         = 0,
        .iir_b1         = 0,
        .iir_b2         = 0,
        .cor_threshold  = 0,
        .cor_level      = 0,
        .fir_filter[0]  = 0,
        .fir_filter[1]  = 0,
        .fir_filter[2]  = 0,
    };

    if( idx == 1 ) {
        for( ch = E_IM_PRO_AF_CH0; ch < E_IM_PRO_AF_CH1 + 1; ch++ ) {
            ercd = Im_PRO_AF_Ctrl_Vertical( ch, &af_ctrl_max );
            if( ercd != D_DDIM_USER_E_OK ) {
                Ddim_Print(( "Im_PRO_AF_Ctrl_Vertical(%u) max_para Error ercd=0x%x\n", ch, ercd ));
            }
            else {
                CT_Im_PRO_4_30_Print( "max_para", ch, &af_ctrl_max );
            }

            ercd = Im_PRO_AF_Ctrl_Vertical( ch, &af_ctrl_min );
            if( ercd != D_DDIM_USER_E_OK ) {
                Ddim_Print(( "Im_PRO_AF_Ctrl_Vertical(%u) min_para Error ercd=0x%x\n", ch, ercd ));
            }
            else {
                CT_Im_PRO_4_30_Print( "min_para", ch, &af_ctrl_min );
            }
        }
    }
}

