    if(IO_PRO.STAT.AF[ch].AFWIN[win_no].AFWINCTL.bit.AFSLWH0 != af_ctrl->h_sel0          ) Ddim_Print(( "Im_PRO_AF_Ctrl_Win(%u %u) %s result:AFSLWH0   0x%08lx(%d) in(%d)\n", ch, win_no, string, (ULONG)&IO_PRO.STAT.AF[ch].AFWIN[win_no].AFWINCTL.word , IO_PRO.STAT.AF[ch].AFWIN[win_no].AFWINCTL.bit.AFSLWH0 ,af_ctrl->h_sel0            ));
