    if(IO_PRO.STAT.AF[ch].AFWIN[win_no].AFH.bit.AFH          != af_ctrl->start_pos_x     ) Ddim_Print(( "Im_PRO_AF_Ctrl_Win(%u %u) %s result:AFH       0x%08lx(%d) in(%d)\n", ch, win_no, string, (ULONG)&IO_PRO.STAT.AF[ch].AFWIN[win_no].AFH.word      , IO_PRO.STAT.AF[ch].AFWIN[win_no].AFH.bit.AFH          ,af_ctrl->start_pos_x       ));
    if(IO_PRO.STAT.AF[ch].AFWIN[win_no].AFV.bit.AFV          != af_ctrl->start_pos_y     ) Ddim_Print(( "Im_PRO_AF_Ctrl_Win(%u %u) %s result:AFV       0x%08lx(%d) in(%d)\n", ch, win_no, string, (ULONG)&IO_PRO.STAT.AF[ch].AFWIN[win_no].AFV.word      , IO_PRO.STAT.AF[ch].AFWIN[win_no].AFV.bit.AFV          ,af_ctrl->start_pos_y       ));
