    if(IO_PRO.STAT.AF[ch].AFWIN[win_no].AFVW.bit.AFVW        != af_ctrl->height          ) Ddim_Print(( "Im_PRO_AF_Ctrl_Win(%u %u) %s result:AFVW      0x%08lx(%d) in(%d)\n", ch, win_no, string, (ULONG)&IO_PRO.STAT.AF[ch].AFWIN[win_no].AFVW.word     , IO_PRO.STAT.AF[ch].AFWIN[win_no].AFVW.bit.AFVW        ,af_ctrl->height            ));
