VOID CT_Im_PRO_5_2( const UINT32 idx )
{
    INT32 ercd;

    if( idx == 1 ) {
//        Ddim_Print(( "Target register address\n" ));
//        Ddim_Print(( "Im_PRO_PASTOP_SW_Reset() SR (0x%08lx, %lx)\n", (ULONG)&IO_PRO.PAS.PASTOP.SR.word,    IO_PRO.PAS.PASTOP.SR.word   ));

        // Normal case
        ercd = Im_PRO_PASTOP_SW_Reset();
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_PASTOP_SW_Reset() Error ercd=0x%x\n", ercd ));
        }
        else {
            Ddim_Print(( "Im_PRO_PASTOP_SW_Reset() result:SR(%u)\n", IO_PRO.PAS.PASTOP.SR.bit.SR ));
        }

        // illegal case
        Im_PRO_SG_Start( E_IM_PRO_SG_CH_0 );

        ercd = Im_PRO_PASTOP_SW_Reset();
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_PASTOP_SW_Reset() Error ercd=0x%x\n", ercd ));
        }
        else {
            Ddim_Print(( "Im_PRO_PASTOP_SW_Reset() result:SR(%u)\n", IO_PRO.PAS.PASTOP.SR.bit.SR ));
        }
        Im_PRO_SG_Stop( E_IM_PRO_SG_CH_0, 0 );
    }
}

VOID CT_Im_PRO_5_3( const UINT32 idx )
{
    INT32 ercd;
    E_IM_PRO_PASTOP_CLK_TYPE clk_type;
    UCHAR on_off;
    UCHAR wait_skip;

    if( idx == 1 ) {
//        Ddim_Print(( "Target register address\n" ));
//        Ddim_Print(( "Im_PRO_PASTOP_Control_Clock() CLKSTP1 (0x%08lx, %lx)\n", (ULONG)&IO_PRO.PAS.PASTOP.CLKSTP.word,  IO_PRO.PAS.PASTOP.CLKSTP.word   ));

        // SENSORCLK ON
        clk_type    = E_IM_PRO_PASTOP_CLK_TYPE_PASCLK;
        on_off      = D_IM_PRO_CLOCK_ON;
        wait_skip   = 0;
        ercd = Im_PRO_PASTOP_Control_Clock( clk_type, on_off, wait_skip );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_PASTOP_Control_Clock( %u, %u, %u ) Error ercd=0x%x\n", clk_type, on_off, wait_skip, ercd ));
        }
        else {
            Ddim_Print(( "Im_PRO_PASTOP_Control_Clock( %u, %u, %u ) result:CLKSTP1(%lu)\n", clk_type, on_off, wait_skip, IO_PRO.PAS.PASTOP.CLKSTP.word ));
        }

        // SENSORCLK OFF
        clk_type    = E_IM_PRO_PASTOP_CLK_TYPE_PASCLK;
        on_off      = D_IM_PRO_CLOCK_OFF;
        wait_skip   = 0;
        ercd = Im_PRO_PASTOP_Control_Clock( clk_type, on_off, wait_skip );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_PASTOP_Control_Clock( %u, %u, %u ) Error ercd=0x%x\n", clk_type, on_off, wait_skip, ercd ));
        }
        else {
            Ddim_Print(( "Im_PRO_PASTOP_Control_Clock( %u, %u, %u ) result:CLKSTP1(%lu)\n", clk_type, on_off, wait_skip, IO_PRO.PAS.PASTOP.CLKSTP.word ));
        }

        // wait skip on
        clk_type    = E_IM_PRO_PASTOP_CLK_TYPE_PASCLK;
        on_off      = D_IM_PRO_CLOCK_ON;
        wait_skip   = 1;
        ercd = Im_PRO_PASTOP_Control_Clock( clk_type, on_off, wait_skip );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_PASTOP_Control_Clock( %u, %u, %u ) Error ercd=0x%x\n", clk_type, on_off, wait_skip, ercd ));
        }
        else {
            Ddim_Print(( "Im_PRO_PASTOP_Control_Clock( %u, %u, %u ) result:CLKSTP1(%lu)\n", clk_type, on_off, wait_skip, IO_PRO.PAS.PASTOP.CLKSTP.word ));
        }

        // wait skip on
        clk_type    = E_IM_PRO_PASTOP_CLK_TYPE_PASCLK;
        on_off      = D_IM_PRO_CLOCK_OFF;
        wait_skip   = 1;
        ercd = Im_PRO_PASTOP_Control_Clock( clk_type, on_off, wait_skip );
        if( ercd != D_DDIM_USER_E_OK ) {
            Ddim_Print(( "Im_PRO_PASTOP_Control_Clock( %u, %u, %u ) Error ercd=0x%x\n", clk_type, on_off, wait_skip, ercd ));
        }
        else {
            Ddim_Print(( "Im_PRO_PASTOP_Control_Clock( %u, %u, %u ) result:CLKSTP1(%lu)\n", clk_type, on_off, wait_skip, IO_PRO.PAS.PASTOP.CLKSTP.word ));
        }
    }
}

