VOID CT_Im_PRO_6_9_Print( const char* string, E_IM_PRO_UNIT_NUM unit_no, E_IM_PRO_BLOCK_TYPE block_type, UCHAR ch, INT32 ercd, T_IM_PRO_PWCH_CTRL* pwch_ctrl )
{
    const T_IM_PRO_COMMON_PWCH_INFO* pwch_info;

    if( ercd == D_DDIM_USER_E_OK ) {
        im_pro_comm_get_pwch_reg_info( unit_no, block_type, ch, &pwch_info );
        if(pwch_info->reg_ptr->PWS.bit.PWS      != pwch_ctrl->trans_to     )    Ddim_Print(( "Im_PRO_PWch_Ctrl(%u %u %u) %s result:PWS      (%d) in(%d)\n", unit_no, block_type, ch, string, pwch_info->reg_ptr->PWS.bit.PWS      , pwch_ctrl->trans_to       ));
        if(pwch_info->reg_ptr->PWCHCTL.bit.PWLV != pwch_ctrl->req_threshold)    Ddim_Print(( "Im_PRO_PWch_Ctrl(%u %u %u) %s result:PWLV     (%d) in(%d)\n", unit_no, block_type, ch, string, pwch_info->reg_ptr->PWCHCTL.bit.PWLV , pwch_ctrl->req_threshold  ));
        if(pwch_info->reg_ptr->PWCHCTL.bit.PWMW != pwch_ctrl->write_mask   )    Ddim_Print(( "Im_PRO_PWch_Ctrl(%u %u %u) %s result:PWMW     (%d) in(%d)\n", unit_no, block_type, ch, string, pwch_info->reg_ptr->PWCHCTL.bit.PWMW , pwch_ctrl->write_mask     ));
        if(pwch_info->reg_ptr->PWVFM.bit.PWVFM  != pwch_ctrl->burst_align_size) Ddim_Print(( "Im_PRO_PWch_Ctrl(%u %u %u) %s result:PWDW     (%d) in(%d)\n", unit_no, block_type, ch, string, pwch_info->reg_ptr->PWDW.bit.PWDW    , pwch_ctrl->burst_align_size  ));
        if(pwch_info->reg_ptr->PWVFM.bit.PWVFM  != pwch_ctrl->output_format)    Ddim_Print(( "Im_PRO_PWch_Ctrl(%u %u %u) %s result:PWVFM    (%d) in(%d)\n", unit_no, block_type, ch, string, pwch_info->reg_ptr->PWVFM.bit.PWVFM  , pwch_ctrl->output_format  ));
    }
    else {
        Ddim_Print(( "Im_PRO_PWch_Ctrl(%u %u %u) error(not exist) ercd=0x%x\n", unit_no, block_type, ch, ercd ));
    }
}

