VOID CT_Im_PRO_6_23_Print( E_IM_PRO_UNIT_NUM unit_no, E_IM_PRO_BLOCK_TYPE block_type, UCHAR           ch, INT32 ercd, const T_IM_PRO_RDMA_PGAIN_ADDR** addr )
{
    const T_IM_PRO_COMMON_PGAIN_INFO* pgain_info;
    if( ercd == D_DDIM_USER_E_OK ) {
        im_pro_comm_get_pgain_reg_info( unit_no, block_type, ch, &pgain_info );
        if((ULONG)&pgain_info->reg_ptr->PGAINR.word  != (*addr)->PGAINR  ) Ddim_Print(( "Im_PRO_Get_RdmaAddr_PGAIN_Cntl(%u %u %u) PGAINR   reg_addr (0x%08lx) rdma_addr(0x%08lx)\n", unit_no, block_type, ch, (ULONG)&pgain_info->reg_ptr->PGAINR.word , (ULONG)(*addr)->PGAINR ));
        if((ULONG)&pgain_info->reg_ptr->PGAINGR.word != (*addr)->PGAINGR ) Ddim_Print(( "Im_PRO_Get_RdmaAddr_PGAIN_Cntl(%u %u %u) PGAINGR  reg_addr (0x%08lx) rdma_addr(0x%08lx)\n", unit_no, block_type, ch, (ULONG)&pgain_info->reg_ptr->PGAINGR.word, (ULONG)(*addr)->PGAINGR));
        if((ULONG)&pgain_info->reg_ptr->PGAINGB.word != (*addr)->PGAINGB ) Ddim_Print(( "Im_PRO_Get_RdmaAddr_PGAIN_Cntl(%u %u %u) PGAINGB  reg_addr (0x%08lx) rdma_addr(0x%08lx)\n", unit_no, block_type, ch, (ULONG)&pgain_info->reg_ptr->PGAINGB.word, (ULONG)(*addr)->PGAINGB));
        if((ULONG)&pgain_info->reg_ptr->PGAINB.word  != (*addr)->PGAINB  ) Ddim_Print(( "Im_PRO_Get_RdmaAddr_PGAIN_Cntl(%u %u %u) PGAINB   reg_addr (0x%08lx) rdma_addr(0x%08lx)\n", unit_no, block_type, ch, (ULONG)&pgain_info->reg_ptr->PGAINB.word , (ULONG)(*addr)->PGAINB ));
        if((ULONG)&pgain_info->reg_ptr->POFSR.word   != (*addr)->POFSR   ) Ddim_Print(( "Im_PRO_Get_RdmaAddr_PGAIN_Cntl(%u %u %u) POFSR    reg_addr (0x%08lx) rdma_addr(0x%08lx)\n", unit_no, block_type, ch, (ULONG)&pgain_info->reg_ptr->POFSR.word  , (ULONG)(*addr)->POFSR  ));
        if((ULONG)&pgain_info->reg_ptr->POFSGR.word  != (*addr)->POFSGR  ) Ddim_Print(( "Im_PRO_Get_RdmaAddr_PGAIN_Cntl(%u %u %u) POFSGR   reg_addr (0x%08lx) rdma_addr(0x%08lx)\n", unit_no, block_type, ch, (ULONG)&pgain_info->reg_ptr->POFSGR.word , (ULONG)(*addr)->POFSGR ));
        if((ULONG)&pgain_info->reg_ptr->POFSGB.word  != (*addr)->POFSGB  ) Ddim_Print(( "Im_PRO_Get_RdmaAddr_PGAIN_Cntl(%u %u %u) POFSGB   reg_addr (0x%08lx) rdma_addr(0x%08lx)\n", unit_no, block_type, ch, (ULONG)&pgain_info->reg_ptr->POFSGB.word , (ULONG)(*addr)->POFSGB ));
        if((ULONG)&pgain_info->reg_ptr->POFSB.word   != (*addr)->POFSB   ) Ddim_Print(( "Im_PRO_Get_RdmaAddr_PGAIN_Cntl(%u %u %u) POFSB    reg_addr (0x%08lx) rdma_addr(0x%08lx)\n", unit_no, block_type, ch, (ULONG)&pgain_info->reg_ptr->POFSB.word  , (ULONG)(*addr)->POFSB  ));
    }
    else {
        Ddim_Print(( "Im_PRO_Get_RdmaAddr_PGAIN_Cntl(%u %u %u) error(not exist) ercd=0x%x\n", unit_no, block_type, ch, ercd ));
    }
}

