VOID CT_Im_PRO_6_30_Print( const char* string, E_IM_PRO_UNIT_NUM unit_no, E_IM_PRO_BLOCK_TYPE block_type, INT32 ercd, T_IM_PRO_PG_CTRL* pg_ctrl )
{
    const T_IM_PRO_COMMON_PG_INFO* pg_info;

    if( ercd == D_DDIM_USER_E_OK ) {
        im_pro_comm_get_pg_reg_info( unit_no, block_type, &pg_info );
        if(pg_info->reg_ptr->PGCTL.bit.PGMD          != pg_ctrl->mode               ) Ddim_Print(( "Im_PRO_PG_Ctrl(%u %u) %s result:PGMD      (%d) in(%d)\n", unit_no, block_type, string, pg_info->reg_ptr->PGCTL.bit.PGMD          , pg_ctrl->mode                  ));
        if(pg_info->reg_ptr->PGVW.bit.PGVW           != pg_ctrl->input_img_lines    ) Ddim_Print(( "Im_PRO_PG_Ctrl(%u %u) %s result:PGVW      (%d) in(%d)\n", unit_no, block_type, string, pg_info->reg_ptr->PGVW.bit.PGVW           , pg_ctrl->input_img_lines       ));
        if(pg_info->reg_ptr->PGHW.bit.PGHW           != pg_ctrl->input_img_width    ) Ddim_Print(( "Im_PRO_PG_Ctrl(%u %u) %s result:PGHW      (%d) in(%d)\n", unit_no, block_type, string, pg_info->reg_ptr->PGHW.bit.PGHW           , pg_ctrl->input_img_width       ));
        if(pg_info->reg_ptr->PGVBLNK.bit.PGVBLNK     != pg_ctrl->vertical_blanking  ) Ddim_Print(( "Im_PRO_PG_Ctrl(%u %u) %s result:PGVBLNK   (%d) in(%d)\n", unit_no, block_type, string, pg_info->reg_ptr->PGVBLNK.bit.PGVBLNK     , pg_ctrl->vertical_blanking     ));
        if(pg_info->reg_ptr->PGHBLNK.bit.PGHBLNK     != pg_ctrl->horizontal_blanking) Ddim_Print(( "Im_PRO_PG_Ctrl(%u %u) %s result:PGHBLNK   (%d) in(%d)\n", unit_no, block_type, string, pg_info->reg_ptr->PGHBLNK.bit.PGHBLNK     , pg_ctrl->horizontal_blanking   ));
        if(pg_info->reg_ptr->PGVDHDBLNK.bit.PGVHBLNK != pg_ctrl->start_blanking     ) Ddim_Print(( "Im_PRO_PG_Ctrl(%u %u) %s result:PGVHBLNK  (%d) in(%d)\n", unit_no, block_type, string, pg_info->reg_ptr->PGVDHDBLNK.bit.PGVHBLNK , pg_ctrl->start_blanking        ));
    }
    else {
        Ddim_Print(( "Im_PRO_PG_Ctrl(%u %u) error(not exist) ercd=0x%x\n", unit_no, block_type, ercd ));
    }
}

