{
    const T_IM_PRO_COMMON_MONI_INFO* moni_info;

    if( ercd == D_DDIM_USER_E_OK ) {
        im_pro_comm_get_moni_reg_info( unit_no, block_type, ch, &moni_info );
        if(moni_info->reg_ptr->MONICTL.bit.MONIMD              != moni_ctrl->monitor_mode                    ) Ddim_Print(( "Im_PRO_MONI_Ctrl(%u %u %u) %s result:MONIMD           (%u)  in(%u)\n", unit_no, block_type, ch, string, moni_info->reg_ptr->MONICTL.bit.MONIMD              , moni_ctrl->monitor_mode                       ));
        if(moni_info->reg_ptr->MONIHDEXP.bit.MONIHDEXP         != moni_ctrl->hd_cnt_expect_val               ) Ddim_Print(( "Im_PRO_MONI_Ctrl(%u %u %u) %s result:MONIHDEXP        (%u)  in(%u)\n", unit_no, block_type, ch, string, moni_info->reg_ptr->MONIHDEXP.bit.MONIHDEXP         , moni_ctrl->hd_cnt_expect_val                  ));
        if(moni_info->reg_ptr->MONIEPFEXP.bit.MONIEPFEXP       != moni_ctrl->valid_pixel_expect_cnt_in_1frame) Ddim_Print(( "Im_PRO_MONI_Ctrl(%u %u %u) %s result:MONIEPFEXP       (%lu) in(%lu)\n", unit_no, block_type, ch, string, moni_info->reg_ptr->MONIEPFEXP.bit.MONIEPFEXP       , moni_ctrl->valid_pixel_expect_cnt_in_1frame   ));
        if(moni_info->reg_ptr->MONIBLLMINEXP.bit.MONIBLLMINEXP != moni_ctrl->lower_limit_except_h_blank      ) Ddim_Print(( "Im_PRO_MONI_Ctrl(%u %u %u) %s result:MONIBLLMINEXP    (%lu) in(%lu)\n", unit_no, block_type, ch, string, moni_info->reg_ptr->MONIBLLMINEXP.bit.MONIBLLMINEXP , moni_ctrl->lower_limit_except_h_blank         ));
        if(moni_info->reg_ptr->MONIBLLMAXEXP.bit.MONIBLLMAXEXP != moni_ctrl->upper_limit_except_h_blank      ) Ddim_Print(( "Im_PRO_MONI_Ctrl(%u %u %u) %s result:MONIBLLMAXEXP    (%lu) in(%lu)\n", unit_no, block_type, ch, string, moni_info->reg_ptr->MONIBLLMAXEXP.bit.MONIBLLMAXEXP , moni_ctrl->upper_limit_except_h_blank         ));
        if(moni_info->reg_ptr->MONIADHD.bit.MONIADHD           != moni_ctrl->additional_hd_cnt               ) Ddim_Print(( "Im_PRO_MONI_Ctrl(%u %u %u) %s result:MONIADHD         (%u)  in(%d)\n", unit_no, block_type, ch, string, moni_info->reg_ptr->MONIADHD.bit.MONIADHD           , moni_ctrl->additional_hd_cnt                  ));
        if(moni_info->reg_ptr->MONIADHW.bit.MONIADHW           != moni_ctrl->additional_hd_gap_cnt           ) Ddim_Print(( "Im_PRO_MONI_Ctrl(%u %u %u) %s result:MONIADHW         (%llu) in(%llu)\n", unit_no, block_type, ch, string, (ULLONG)moni_info->reg_ptr->MONIADHW.bit.MONIADHW           , moni_ctrl->additional_hd_gap_cnt              ));
    }
    else {
        Ddim_Print(( "Im_PRO_MONI_Ctrl(%u %u %u) error(not exist) ercd=0x%x\n", unit_no, block_type, ch, ercd ));
    }
}

