VOID CT_Im_PRO_6_37_Print( const char* string, E_IM_PRO_UNIT_NUM unit_no, E_IM_PRO_BLOCK_TYPE block_type, UCHAR           ch, INT32 ercd, T_IM_PRO_M2P_CTRL* m2p_ctrl )
{
    const T_IM_PRO_COMMON_M2P_INFO* m2p_info;

    if( ercd == D_DDIM_USER_E_OK ) {
        im_pro_comm_get_m2p_reg_info( unit_no, block_type, ch, &m2p_info );
        if(m2p_info->reg_ptr->M2PCTL.bit.M2PTYP     != m2p_ctrl->data_type             ) Ddim_Print(( "Im_PRO_M2P_Ctrl(%u %u %u) %s result:M2PTYP        (%d) in(%d)\n", unit_no, block_type, ch, string, m2p_info->reg_ptr->M2PCTL.bit.M2PTYP     , m2p_ctrl->data_type              ));
        if(m2p_info->reg_ptr->M2PCTL.bit.MDKNMD     != m2p_ctrl->deknee_enable         ) Ddim_Print(( "Im_PRO_M2P_Ctrl(%u %u %u) %s result:MDKNMD        (%d) in(%d)\n", unit_no, block_type, ch, string, m2p_info->reg_ptr->M2PCTL.bit.MDKNMD     , m2p_ctrl->deknee_enable          ));
        if(m2p_info->reg_ptr->M2PBSFT.bit.M2PBSFT   != m2p_ctrl->shift_bit             ) Ddim_Print(( "Im_PRO_M2P_Ctrl(%u %u %u) %s result:M2PBSFT       (%d) in(%d)\n", unit_no, block_type, ch, string, m2p_info->reg_ptr->M2PBSFT.bit.M2PBSFT   , m2p_ctrl->shift_bit              ));
        if(m2p_info->reg_ptr->M2PBSFT.bit.M2PBMD    != m2p_ctrl->shift_sat             ) Ddim_Print(( "Im_PRO_M2P_Ctrl(%u %u %u) %s result:M2PBMD        (%d) in(%d)\n", unit_no, block_type, ch, string, m2p_info->reg_ptr->M2PBSFT.bit.M2PBMD    , m2p_ctrl->shift_sat              ));
        if(m2p_info->reg_ptr->M2PBSFT.bit.M2PBLR    != m2p_ctrl->bit_shift             ) Ddim_Print(( "Im_PRO_M2P_Ctrl(%u %u %u) %s result:M2PBLR        (%d) in(%d)\n", unit_no, block_type, ch, string, m2p_info->reg_ptr->M2PBSFT.bit.M2PBLR    , m2p_ctrl->bit_shift              ));
        if(m2p_info->reg_ptr->M2PBSFT.bit.M2PBT     != m2p_ctrl->valid_bit_count       ) Ddim_Print(( "Im_PRO_M2P_Ctrl(%u %u %u) %s result:M2PBT         (%d) in(%d)\n", unit_no, block_type, ch, string, m2p_info->reg_ptr->M2PBSFT.bit.M2PBT     , m2p_ctrl->valid_bit_count        ));
        if(m2p_info->reg_ptr->M2POFS.bit.M2POFS     != m2p_ctrl->shift_value           ) Ddim_Print(( "Im_PRO_M2P_Ctrl(%u %u %u) %s result:M2POFS        (%d) in(%d)\n", unit_no, block_type, ch, string, m2p_info->reg_ptr->M2POFS.bit.M2POFS     , m2p_ctrl->shift_value            ));
        if(m2p_info->reg_ptr->M2PCLIP.bit.M2PCLIPLW != m2p_ctrl->lower_limit_clip_value) Ddim_Print(( "Im_PRO_M2P_Ctrl(%u %u %u) %s result:M2PCLIPLW     (%d) in(%d)\n", unit_no, block_type, ch, string, m2p_info->reg_ptr->M2PCLIP.bit.M2PCLIPLW , m2p_ctrl->lower_limit_clip_value ));
        if(m2p_info->reg_ptr->M2PCLIP.bit.M2PCLIPHI != m2p_ctrl->upper_limit_clip_value) Ddim_Print(( "Im_PRO_M2P_Ctrl(%u %u %u) %s result:M2PCLIPHI     (%d) in(%d)\n", unit_no, block_type, ch, string, m2p_info->reg_ptr->M2PCLIP.bit.M2PCLIPHI , m2p_ctrl->upper_limit_clip_value ));
    }
    else {
        Ddim_Print(( "Im_PRO_M2P_Ctrl(%u %u %u) error(not exist) ercd=0x%x\n", unit_no, block_type, ch, ercd ));
    }
}

