VOID CT_Im_PRO_6_43_Print( const char* string, E_IM_PRO_UNIT_NUM unit_no, E_IM_PRO_BLOCK_TYPE block_type, UCHAR ch, INT32 ercd, T_IM_PRO_PRCH_CTRL* prch_ctrl )
{
    const T_IM_PRO_COMMON_PRCH_INFO* prch_info;

    if( ercd == D_DDIM_USER_E_OK ) {
        im_pro_comm_get_prch_reg_info( unit_no, block_type, ch, &prch_info );
        if(prch_info->reg_ptr->PRCHCTL.bit.PRBMD != prch_ctrl->trans_mode   ) Ddim_Print(( "Im_PRO_PRch_Ctrl(%u %u %u) %s result:PRBMD    (%d) in(%d)\n", unit_no, block_type, ch, string, prch_info->reg_ptr->PRCHCTL.bit.PRBMD , prch_ctrl->trans_mode    ));
        if(prch_info->reg_ptr->PRCHCTL.bit.PRLV  != prch_ctrl->req_threshold) Ddim_Print(( "Im_PRO_PRch_Ctrl(%u %u %u) %s result:PRLV     (%d) in(%d)\n", unit_no, block_type, ch, string, prch_info->reg_ptr->PRCHCTL.bit.PRLV  , prch_ctrl->req_threshold ));
        if(prch_info->reg_ptr->PRCHRS.bit.PRS    != prch_ctrl->trans_to     ) Ddim_Print(( "Im_PRO_PRch_Ctrl(%u %u %u) %s result:PRS      (%d) in(%d)\n", unit_no, block_type, ch, string, prch_info->reg_ptr->PRCHRS.bit.PRS    , prch_ctrl->trans_to      ));
    }
    else {
        Ddim_Print(( "Im_PRO_PRch_Ctrl(%u %u %u) error(not exist) ercd=0x%x\n", unit_no, block_type, ch, ercd ));
    }
}

