VOID CT_Im_PRO_7_15_Print( INT32 ercd, T_IM_PRO_INT_SENTOP_CTRL* int_ctrl, UCHAR permission_flg )
{
    if( ercd == D_DDIM_USER_E_OK ) {
        Ddim_Print(( "Im_PRO_SENTOP_Interrupt_Ctrl() INTMD(%u %u)\n", IO_PRO.SEN.SENTOP.INTCTL.bit.INTMD, int_ctrl->int_mode  ));
        Ddim_Print(( "Im_PRO_SENTOP_Interrupt_Ctrl(%u) VHDINTFLG1(0x%08lx) VHDINTENB1(0x%08lx) input_param(%lu) AND(0x%08lx)\n", permission_flg, IO_PRO.SEN.SENTOP.VHDINTFLG.VHDINTFLG1.word, IO_PRO.SEN.SENTOP.VHDINTENB.VHDINTENB1.word, int_ctrl->vd_enable.interrupt_bit, ( IO_PRO.SEN.SENTOP.VHDINTENB.VHDINTENB1.word & int_ctrl->vd_enable.interrupt_bit )   ));
        Ddim_Print(( "Im_PRO_SENTOP_Interrupt_Ctrl(%u) VHDINTFLG2(0x%08lx) VHDINTENB2(0x%08lx) input_param(%lu) AND(0x%08lx)\n", permission_flg, IO_PRO.SEN.SENTOP.VHDINTFLG.VHDINTFLG2.word, IO_PRO.SEN.SENTOP.VHDINTENB.VHDINTENB2.word, int_ctrl->hd_enable.interrupt_bit, ( IO_PRO.SEN.SENTOP.VHDINTENB.VHDINTENB2.word & int_ctrl->hd_enable.interrupt_bit )   ));
    }
    else {
        Ddim_Print(( "Im_PRO_SENTOP_Interrupt_Ctrl(%u) error ercd=0x%x\n", permission_flg, ercd ));
    }
}

VOID CT_Im_PRO_7_15( const UINT32 idx )
{
    INT32 ercd;
    UCHAR permission_flg;
    UCHAR  int_mode;
    T_IM_PRO_INT_SENTOP_CTRL int_ctrl = {
        .int_mode                   = E_IM_PRO_INT_INTMD_ORAND,
        .vd_enable.interrupt_bit    = 0,
        .vd_enable.permission_flg   = 0,
        .hd_enable.interrupt_bit    = 0,
        .hd_enable.permission_flg   = 0,
    };

    if( idx == 1 ) {
        for( permission_flg = 0; permission_flg < 2; permission_flg++ ) {
            for( int_mode = E_IM_PRO_INT_INTMD_OR; int_mode < E_IM_PRO_INT_INTMD_ORAND + 1; int_mode++ ) {
                int_ctrl.vd_enable.permission_flg   = permission_flg;
                int_ctrl.hd_enable.permission_flg   = permission_flg;

                int_ctrl.vd_enable.interrupt_bit        =   (   D_IM_PRO_INT_VDE00 |
                                                                D_IM_PRO_INT_VDE01 |
                                                                D_IM_PRO_INT_VDE10 |
                                                                D_IM_PRO_INT_VDE11 |
                                                                D_IM_PRO_INT_VDE20 |
                                                                D_IM_PRO_INT_VDE21 |
                                                                D_IM_PRO_INT_VDE30 |
                                                                D_IM_PRO_INT_VDE31  );
                int_ctrl.hd_enable.interrupt_bit        =   (   D_IM_PRO_INT_HDE00 |
                                                                D_IM_PRO_INT_HDE01 |
                                                                D_IM_PRO_INT_HDE10 |
                                                                D_IM_PRO_INT_HDE11 |
                                                                D_IM_PRO_INT_HDE20 |
                                                                D_IM_PRO_INT_HDE21 |
                                                                D_IM_PRO_INT_HDE30 |
                                                                D_IM_PRO_INT_HDE31  );

                int_ctrl.int_mode   =   int_mode;
#ifdef CO_DEBUG_ON_PC
                IO_PRO.SEN.SENTOP.VHDINTFLG.VHDINTFLG1.word = 0xFFFFFFFF;
                IO_PRO.SEN.SENTOP.VHDINTFLG.VHDINTFLG2.word = 0xFFFFFFFF;
#endif  // CO_DEBUG_ON_PC
                ercd = Im_PRO_SENTOP_Interrupt_Ctrl( &int_ctrl );
                CT_Im_PRO_7_15_Print( ercd, &int_ctrl, permission_flg );
            }
        }
    }
}


