VOID CT_Im_PRO_7_18( const UINT32 idx )
{
    INT32 ercd;
    UCHAR block_num;
    UCHAR ch;
    T_IM_PRO_INT_VHD_DELAY_CTRL int_ctrl_max = {
        .hd_delay   = 12288,
        .vd_h_delay = 12288,
        .vd_v_delay = 16383,
    };

    T_IM_PRO_INT_VHD_DELAY_CTRL int_ctrl_min = {
        .hd_delay   = 0,
        .vd_h_delay = 0,
        .vd_v_delay = 0,
    };

    if( idx == 1 ) {
        for( block_num = 0; block_num < 4; block_num++ ) {
            for( ch = 0; ch < 2; ch++ ) {
                ercd = Im_PRO_SENTOP_Set_VHD_Delay( block_num, ch, &int_ctrl_max );
                CT_Im_PRO_7_18_Print( "max_para", block_num, ch, ercd, &int_ctrl_max );

                ercd = Im_PRO_SENTOP_Set_VHD_Delay( block_num, ch, &int_ctrl_min );
                CT_Im_PRO_7_18_Print( "min_para", block_num, ch, ercd, &int_ctrl_min );
            }
        }
    }
}

