VOID CT_Im_PRO_PWCH_INT_CB( T_CALLBACK_ID* cb_id, ULONG result, ULONG user_param )
{
    INT32   ercd;
    ULONG   current_addr = 0;
    ULONG   last_addr = 0;
    UCHAR   axi_response = 0;
    ULONG   data_address;

    last_addr = Im_PRO_PWch_Get_Buf_Data( cb_id->unit_no, cb_id->block_type, cb_id->channel );
    ercd = Im_PRO_PWch_Update_Buf_Index( cb_id->unit_no, cb_id->block_type, cb_id->channel );
    CT_Im_PRO_6_13_Print( 0, cb_id->unit_no, cb_id->block_type, cb_id->channel, ercd );
    current_addr = Im_PRO_PWch_Get_Buf_Data( cb_id->unit_no, cb_id->block_type, cb_id->channel );
    Ddim_Print(( "Im_PRO_PWch_Get_Buf_Data(%u %u %u) LastAddr(0x%08lx) CurrentAddr(0x%08lx)\n", cb_id->unit_no, cb_id->block_type, cb_id->channel, last_addr, current_addr  ));

    ercd = Im_PRO_PWch_Get_AXI_Response(cb_id->unit_no, cb_id->block_type, cb_id->channel, &axi_response);
    CT_Im_PRO_6_15_Print( cb_id->unit_no, cb_id->block_type, cb_id->channel, ercd, axi_response );

    if( cb_id->block_type == E_IM_PRO_BLOCK_TYPE_STAT ) {
        data_address = Im_PRO_AEAWB_Get_AEAWBData( cb_id->channel );
        if( data_address == 0 ) {
            Ddim_Print(( "Im_PRO_AEAWB_Get_AEAWBData(%u) max_para Error\n", cb_id->channel ));
        }
        else {
            CT_Im_PRO_4_21_Print( "", cb_id->channel, &data_address );
        }

        data_address = Im_PRO_AEAWB_Get_LastAEAWBData( cb_id->channel );
        if( data_address == 0 ) {
            Ddim_Print(( "Im_PRO_AEAWB_Get_LastAEAWBData(%u) max_para Error\n", cb_id->channel ));
        }
        else {
            CT_Im_PRO_4_22_Print( "", cb_id->channel, &data_address );
        }
    }
    Ddim_Print(( "CT_Im_PRO_PWCH_INT_CB( %u %u %u 0x%08lx %lu )\n", cb_id->unit_no, cb_id->block_type, cb_id->channel, result, user_param ));
}

