        IO_PRO.STAT.AF[ch].AFWIN[ i - 1 ].AFDATAV.word              = 0x10000000;
        IO_PRO.STAT.AF[ch].AFWIN[ i - 1 ].AFDATAMAX.bit.AFDATAMAX   = 0xFFF;
        IO_PRO.STAT.AF[ch].AFWIN[ i - 1 ].AFDATAMIN.bit.AFDATAMIN   = 0xFFF;
        IO_PRO.STAT.AF[ch].AFWIN[ i - 1 ].AFDATAMAX.bit.AFDATAMAXE  = 0xFFF;
        IO_PRO.STAT.AF[ch].AFWIN[ i - 1 ].AFDATAMIN.bit.AFDATAMINE  = 0xFFF;
        IO_PRO.STAT.AF[ch].AFWIN[ i - 1 ].AFDATAMH0.word            = 0x10000000;
        IO_PRO.STAT.AF[ch].AFWIN[ i - 1 ].AFDATAMH1.word            = 0x10000000;
