VOID CT_Im_PRO_7_23( const UINT32 idx )
{
#ifdef CO_DEBUG_ON_PC
    UINT32  loopcnt;
    UINT32  ch_loopcnt;
    UINT32  inte = 0;
    UINT32  intf = 0;
    inte    = ( D_IM_PRO_PWCHINTENB_PWE     |
                D_IM_PRO_PWCHINTENB_PWEE    |
                D_IM_PRO_PWCHINTENB_PWXE    );
    intf    = ( D_IM_PRO_PWCHINTFLG_PWF     |
                D_IM_PRO_PWCHINTFLG_PWEF    |
                D_IM_PRO_PWCHINTFLG_PWXF    );
    for( ch_loopcnt = 0; ch_loopcnt < E_IM_PRO_PWCH_MAX; ch_loopcnt++ ) {
        ct_im_pro_pwch_intflg_fill( 0, 0, ch_loopcnt, inte, intf );
    }

    inte    = D_IM_PRO_LDIVINTENB_LDIVEE;
    intf    = D_IM_PRO_LDIVINTFLG_LDIVEF;
    for( ch_loopcnt = 0; ch_loopcnt < D_IM_PRO_SEN_LDIV_NUM; ch_loopcnt++ ) {
        ct_im_pro_ldiv_intflg_fill( ch_loopcnt, inte, intf );
    }

    for( loopcnt = 0; loopcnt < D_IM_PRO_SENTOP_BLOB_NUM; loopcnt++ ) {
        for( ch_loopcnt = 0; ch_loopcnt < D_IM_PRO_SEN_OBD_CH_NUM; ch_loopcnt++ ) {
            inte    = D_IM_PRO_OBDINTENB_OBDE;
            intf    = D_IM_PRO_OBDINTFLG_OBDF;
            ct_im_pro_obd_intflg_fill( loopcnt, ch_loopcnt, inte, intf );

            inte    = D_IM_PRO_OBTINTENB_OBTE;
            intf    = D_IM_PRO_OBTINTFLG_OBTF;
            ct_im_pro_obt_intflg_fill( loopcnt, ch_loopcnt, inte, intf );

            IO_PRO.SEN.OBD[loopcnt][ch_loopcnt].OBDCORE.OBDDATAR.bit.OBDDATAR   = 0xFFFFFFFF;
            IO_PRO.SEN.OBD[loopcnt][ch_loopcnt].OBDCORE.OBDDATAGR.bit.OBDDATAGR = 0xFFFFFFFF;
            IO_PRO.SEN.OBD[loopcnt][ch_loopcnt].OBDCORE.OBDDATAGB.bit.OBDDATAGB = 0xFFFFFFFF;
            IO_PRO.SEN.OBD[loopcnt][ch_loopcnt].OBDCORE.OBDDATAB.bit.OBDDATAB   = 0xFFFFFFFF;
            IO_PRO.SEN.OBD[loopcnt][ch_loopcnt].OBDCORE.OBDCNTR.bit.OBDCNTR     = 0xFFFFF;
            IO_PRO.SEN.OBD[loopcnt][ch_loopcnt].OBDCORE.OBDCNTGR.bit.OBDCNTGR   = 0xFFFFF;
            IO_PRO.SEN.OBD[loopcnt][ch_loopcnt].OBDCORE.OBDCNTGB.bit.OBDCNTGB   = 0xFFFFF;
            IO_PRO.SEN.OBD[loopcnt][ch_loopcnt].OBDCORE.OBDCNTB.bit.OBDCNTB     = 0xFFFFF;

            IO_PRO.SEN.OBT[loopcnt][ch_loopcnt].OBTCORE.OBTDATAR.bit.OBTDATAR   = 0x3FFF;
            IO_PRO.SEN.OBT[loopcnt][ch_loopcnt].OBTCORE.OBTDATAGR.bit.OBTDATAGR = 0x3FFF;
            IO_PRO.SEN.OBT[loopcnt][ch_loopcnt].OBTCORE.OBTDATAGB.bit.OBTDATAGB = 0x3FFF;
            IO_PRO.SEN.OBT[loopcnt][ch_loopcnt].OBTCORE.OBTDATAB.bit.OBTDATAB   = 0x3FFF;
        }
    }

#endif  // CO_DEBUG_ON_PC
    Im_PRO_SEN_Int_Handler();
}

