VOID CT_Im_PRO_7_40_Print( INT32 ercd, E_IM_PRO_UNIT_NUM unit_no, E_IM_PRO_BLOCK_TYPE block_type, UCHAR ch, T_IM_PRO_INT_CFG* int_ctrl, UCHAR permission_flg )
{
    const T_IM_PRO_COMMON_MONI_INFO* moni_info;

    if( ercd == D_DDIM_USER_E_OK ) {
        im_pro_comm_get_moni_reg_info( unit_no, block_type, ch, &moni_info );
        Ddim_Print(( "Im_PRO_MONI_Set_Interrupt(%u %u %u %u) MONIINTFLG0(0x%08lx) MONIINTENB0(0x%08lx) input_param(%lu) AND(0x%08lx)\n",    unit_no,
                                                                                                                                            block_type,
                                                                                                                                            ch,
                                                                                                                                            permission_flg,
                                                                                                                                            moni_info->reg_ptr->MONIINTENB.word,
                                                                                                                                            moni_info->reg_ptr->MONIINTFLG.word,
                                                                                                                                            int_ctrl->interrupt_bit,
                                                                                                                                            ( moni_info->reg_ptr->MONIINTENB.word & int_ctrl->interrupt_bit )    ));
    }
    else {
        Ddim_Print(( "Im_PRO_MONI_Set_Interrupt(%u %u %u %u) error ercd=0x%x\n", unit_no, block_type, ch, permission_flg, ercd ));
    }
}

VOID CT_Im_PRO_7_40( const UINT32 idx )
{
    INT32 ercd;
    UCHAR permission_flg;
    E_IM_PRO_UNIT_NUM unit_no;
    E_IM_PRO_BLOCK_TYPE block_type;
    UCHAR ch;
    T_IM_PRO_INT_CFG int_ctrl = {
        .interrupt_bit  = 0,
        .permission_flg = 0,
    };
#ifdef CO_DEBUG_ON_PC
    const T_IM_PRO_COMMON_MONI_INFO* moni_info;
#endif  // CO_DEBUG_ON_PC

    if( idx == 1 ) {
        for( unit_no = E_IM_PRO_UNIT_NUM_1; unit_no < E_IM_PRO_UNIT_NUM_MAX; unit_no++ ) {
            for( block_type = E_IM_PRO_BLOCK_TYPE_SEN; block_type < E_IM_PRO_BLOCK_TYPE_MAX; block_type++ ) {
                for( ch = 0; ch < D_IM_PRO_SEN_MONI_CH_NUM; ch++ ) {
                    for( permission_flg = 0; permission_flg < 2; permission_flg++ ) {
                        int_ctrl.permission_flg = permission_flg;

                        int_ctrl.interrupt_bit  =   (   D_IM_PRO_MONIINTENB_MONIHDE     |
                                                        D_IM_PRO_MONIINTENB_MONIEPFE    |
                                                        D_IM_PRO_MONIINTENB_MONIEPLE    |
                                                        D_IM_PRO_MONIINTENB_MONIBLLMINE |
                                                        D_IM_PRO_MONIINTENB_MONIBLLMAXE );
#ifdef CO_DEBUG_ON_PC
                        im_pro_comm_get_moni_reg_info( unit_no, block_type, ch, &moni_info );
                        moni_info->reg_ptr->MONIINTFLG.word = int_ctrl.interrupt_bit;
#endif  // CO_DEBUG_ON_PC

                        ercd = Im_PRO_MONI_Set_Interrupt( unit_no, block_type, ch, &int_ctrl );
                        CT_Im_PRO_7_40_Print( ercd, unit_no, block_type, ch, &int_ctrl, permission_flg );
                    }
                }
            }
        }
    }
}

