VOID CT_Im_PRO_7_59_Print( INT32 ercd, E_IM_PRO_UNIT_NUM unit_no, E_IM_PRO_SDC_CH ch, T_IM_PRO_INT_CFG* int_ctrl, UCHAR permission_flg )
{
    if( ercd == D_DDIM_USER_E_OK ) {
        Ddim_Print(( "Im_PRO_SDC_Set_Interrupt(%u %u %u) SDCINTFLG(0x%08lx) SDCINTENB(0x%08lx) input_param(%lu) AND(0x%08lx)\n",    unit_no,
                                                                                                                                    ch,
                                                                                                                                    permission_flg,
                                                                                                                                    IO_PRO.IMG_PIPE[unit_no].SRO.SDC[ch].SDCINTENB.word,
                                                                                                                                    IO_PRO.IMG_PIPE[unit_no].SRO.SDC[ch].SDCINTFLG.word,
                                                                                                                                    int_ctrl->interrupt_bit,
                                                                                                                                    ( IO_PRO.IMG_PIPE[unit_no].SRO.SDC[ch].SDCINTENB.word & int_ctrl->interrupt_bit )   ));
    }
    else {
        Ddim_Print(( "Im_PRO_SDC_Set_Interrupt(%u %u %u) error ercd=0x%x\n", unit_no, ch, permission_flg, ercd ));
    }
}

VOID CT_Im_PRO_7_59( const UINT32 idx )
{
    INT32 ercd;
    UCHAR permission_flg;
    E_IM_PRO_UNIT_NUM unit_no;
    UCHAR ch;
    T_IM_PRO_INT_CFG int_ctrl = {
        .interrupt_bit  = 0,
        .permission_flg = 0,
    };

    if( idx == 1 ) {
        for( unit_no = 0; unit_no < E_IM_PRO_BOTH_UNIT; unit_no++ ) {
            for( ch = 0; ch < D_IM_PRO_SRO_SDC_CH_NUM; ch++ ) {
                for( permission_flg = 0; permission_flg < 2; permission_flg++ ) {
                    int_ctrl.permission_flg = permission_flg;

                    int_ctrl.interrupt_bit  =   D_IM_PRO_SDCINTENB_SDCE;
#ifdef CO_DEBUG_ON_PC
                    IO_PRO.IMG_PIPE[unit_no].SRO.SDC[ch].SDCINTFLG.word = int_ctrl.interrupt_bit;
#endif  // CO_DEBUG_ON_PC

                    ercd = Im_PRO_SDC_Set_Interrupt( unit_no, ch, &int_ctrl );
                    CT_Im_PRO_7_59_Print( ercd, unit_no, ch, &int_ctrl, permission_flg );
                }
            }
        }
    }
}

