            if(IO_PRO.IMG_PIPE[unit_no].B2B.B2BTOP.VMIHADR.bit.VMIHADR1 != int_ctrl->vd_h_delay) Ddim_Print(( "Im_PRO_B2BTOP_Set_VHD_Delay(%u %u) %s VMIHADR1(0x%08lx %d) input_param(%d)\n",    unit_no, ch, string, (ULONG)&IO_PRO.IMG_PIPE[unit_no].B2B.B2BTOP.VMIHADR.word, IO_PRO.IMG_PIPE[unit_no].B2B.B2BTOP.VMIHADR.bit.VMIHADR1, int_ctrl->vd_h_delay      ));
