VOID CT_Im_PRO_7_81_Print( const char* string, UCHAR ch, INT32 ercd, T_IM_PRO_INT_VHD_DELAY_CTRL* int_ctrl )
{
    if( ercd == D_DDIM_USER_E_OK ) {
        if( ch == 0 ) {
            if(IO_PRO.PAS.PASTOP.HMIHADR.bit.HMIHADR0 != int_ctrl->hd_delay  ) Ddim_Print(( "Im_PRO_PASTOP_Set_VHD_Delay(%u) %s HMIHADR(0x%08lx %d) input_param(%u)\n",    ch, string, (ULONG)&IO_PRO.PAS.PASTOP.HMIHADR.word, IO_PRO.PAS.PASTOP.HMIHADR.bit.HMIHADR0, int_ctrl->hd_delay     ));
            if(IO_PRO.PAS.PASTOP.VMIHADR.bit.VMIHADR0 != int_ctrl->vd_h_delay) Ddim_Print(( "Im_PRO_PASTOP_Set_VHD_Delay(%u) %s VMIHADR(0x%08lx %d) input_param(%u)\n",    ch, string, (ULONG)&IO_PRO.PAS.PASTOP.VMIHADR.word, IO_PRO.PAS.PASTOP.VMIHADR.bit.VMIHADR0, int_ctrl->vd_h_delay   ));
            if(IO_PRO.PAS.PASTOP.VMIVADR.bit.VMIVADR0 != int_ctrl->vd_v_delay) Ddim_Print(( "Im_PRO_PASTOP_Set_VHD_Delay(%u) %s VMIVADR(0x%08lx %d) input_param(%u)\n",    ch, string, (ULONG)&IO_PRO.PAS.PASTOP.VMIVADR.word, IO_PRO.PAS.PASTOP.VMIVADR.bit.VMIVADR0, int_ctrl->vd_v_delay   ));
        }
        else {
            if(IO_PRO.PAS.PASTOP.HMIHADR.bit.HMIHADR1 != int_ctrl->hd_delay  ) Ddim_Print(( "Im_PRO_PASTOP_Set_VHD_Delay(%u) %s HMIHADR(0x%08lx %d) input_param(%u)\n",    ch, string, (ULONG)&IO_PRO.PAS.PASTOP.HMIHADR.word, IO_PRO.PAS.PASTOP.HMIHADR.bit.HMIHADR1, int_ctrl->hd_delay     ));
            if(IO_PRO.PAS.PASTOP.VMIHADR.bit.VMIHADR1 != int_ctrl->vd_h_delay) Ddim_Print(( "Im_PRO_PASTOP_Set_VHD_Delay(%u) %s VMIHADR(0x%08lx %d) input_param(%u)\n",    ch, string, (ULONG)&IO_PRO.PAS.PASTOP.VMIHADR.word, IO_PRO.PAS.PASTOP.VMIHADR.bit.VMIHADR1, int_ctrl->vd_h_delay   ));
            if(IO_PRO.PAS.PASTOP.VMIVADR.bit.VMIVADR1 != int_ctrl->vd_v_delay) Ddim_Print(( "Im_PRO_PASTOP_Set_VHD_Delay(%u) %s VMIVADR(0x%08lx %d) input_param(%u)\n",    ch, string, (ULONG)&IO_PRO.PAS.PASTOP.VMIVADR.word, IO_PRO.PAS.PASTOP.VMIVADR.bit.VMIVADR1, int_ctrl->vd_v_delay   ));
        }
    }
    else {
        Ddim_Print(( "Im_PRO_PASTOP_Set_VHD_Delay(%u) error ercd=0x%x\n", ch, ercd ));
    }
}

