VOID CT_Im_PRO_7_91( const UINT32 idx )
{
    INT32 ercd;
    E_IM_PRO_UNIT_NUM unit_no;
    E_IM_PRO_BLOCK_TYPE block_type;
    UCHAR ch;
    ULONG user_param;
    T_IM_PRO_CALLBACK_CFG int_ctrl = {
        .inthandler = NULL,
        .user_param = 0,
    };

    if( idx == 1 ) {
        for( unit_no = E_IM_PRO_UNIT_NUM_1; unit_no < E_IM_PRO_UNIT_NUM_MAX; unit_no++ ) {
            for( block_type = E_IM_PRO_BLOCK_TYPE_SEN; block_type < E_IM_PRO_BLOCK_TYPE_MAX; block_type++ ) {
                for( ch = 0; ch < E_IM_PRO_PRCH_MAX; ch++ ) {
                    for( user_param = 0; user_param < 4; user_param++ ) {
                        int_ctrl.inthandler = CT_Im_PRO_PRCH_INT_CB;
                        int_ctrl.user_param = user_param;
                        ercd = Im_PRO_PRch_Set_Int_Handler( unit_no, block_type, ch, &int_ctrl );
                        CT_Im_PRO_7_91_Print( "", unit_no, block_type, ch,  ercd, &int_ctrl );
                    }
                }
            }
        }
    }
}


