        if(IO_PRO.SEN.SENTOP.PHY1CLKCTL.bit.PHY1_CLKOUTLEN  != clk_ctrl[1].clkoutlen ) Ddim_Print(( "Im_PRO_SENTOP_CPHY_Clk_Ctrl() result:PHY1_CLKOUTLEN    (%d) in(%d)\n", IO_PRO.SEN.SENTOP.PHY1CLKCTL.bit.PHY1_CLKOUTLEN ,clk_ctrl[1].clkoutlen   ));
        if(IO_PRO.SEN.SENTOP.PHY2CLKCTL.bit.PHY2_CLKLANESEL != clk_ctrl[2].clklanesel) Ddim_Print(( "Im_PRO_SENTOP_CPHY_Clk_Ctrl() result:PHY2_CLKLANESEL   (%d) in(%d)\n", IO_PRO.SEN.SENTOP.PHY2CLKCTL.bit.PHY2_CLKLANESEL,clk_ctrl[2].clklanesel  ));
