        if(IO_PRO.SEN.SENTOP.PHY3CLKCTL.bit.PHY3_CLKMODESEL != clk_ctrl[3].clkmodesel) Ddim_Print(( "Im_PRO_SENTOP_CPHY_Clk_Ctrl() result:PHY3_CLKMODESEL   (%d) in(%d)\n", IO_PRO.SEN.SENTOP.PHY3CLKCTL.bit.PHY3_CLKMODESEL,clk_ctrl[3].clkmodesel  ));
