        if(IO_PRO.SEN.SENTOP.BIASCTL.bit.PHY1_XBGRPD != bias_ctrl.phy1_xbgrpd) Ddim_Print(( "Im_PRO_SENTOP_CPHY_Bias_Ctrl() result:PHY0_CLKLANESEL   (%u) in(%u)\n", IO_PRO.SEN.SENTOP.BIASCTL.bit.PHY1_XBGRPD ,bias_ctrl.phy1_xbgrpd  ));
