	// wait 5us
	Dd_ARM_Wait_ns( 5 * 1000 );

	// While waiting, ComboRx Setting Signals & SLVS-EC interface signals are set to valid value 
    ret = Im_PRO_SENTOP_CPHY_Ctrl( &cphy_ctrl );
    if( ret != D_DDIM_USER_E_OK ) {
        Ddim_Print(( "Im_PRO_SENTOP_CPHY_Ctrl() min_para Error ret=0x%x\n", ret ));
    }
    else {
        CT_Im_PRO_1_11_Print( "", &cphy_ctrl );
    }

	mode_ctrl[0].common_ctrl.bitwidthsel			= 1;	// 10bit
	mode_ctrl[1].common_ctrl.bitwidthsel			= 1;	// 10bit
	mode_ctrl[2].common_ctrl.bitwidthsel			= 1;	// 10bit
	mode_ctrl[3].common_ctrl.bitwidthsel			= 1;	// 10bit

	// PHY0
	mode_ctrl[0].common_ctrl.rxmode					= 3;	// SLVS-EC 
	mode_ctrl[0].common_ctrl.d0setsel				= 0;	// ComboRx be inputed Reference Clock from Image Sensor directly
	mode_ctrl[0].common_ctrl.d1setsel				= 0;	// ComboRx be inputed Reference Clock from Image Sensor directly
	mode_ctrl[0].common_ctrl.d2setsel				= 0;	// ComboRx be inputed Reference Clock from Image Sensor directly
	mode_ctrl[0].common_ctrl.d3setsel				= 0;	// ComboRx be inputed Reference Clock from Image Sensor directly
	mode_ctrl[0].pimode								= 1;	// 2.3Gbps-Mode (default) 
	mode_ctrl[0].picnt								= 0;	// normal (default) 

