        if(IO_PRO.SEN.SENTOP.PHY0MDCTL.bit.PHY0_RXMODE              != mode_ctrl[0].common_ctrl.rxmode      ) Ddim_Print(( "Im_PRO_SENTOP_CPHY_Slvs_Mode_Ctrl() result:PHY0_RXMODE      (%u) in(%u)\n", IO_PRO.SEN.SENTOP.PHY0MDCTL.bit.PHY0_RXMODE                , mode_ctrl[0].common_ctrl.rxmode       ));
        if(IO_PRO.SEN.SENTOP.PHY0IFCTL.PHY0IFCTL1.bit.PHY0_D0SETSEL != mode_ctrl[0].common_ctrl.d0setsel    ) Ddim_Print(( "Im_PRO_SENTOP_CPHY_Slvs_Mode_Ctrl() result:PHY0_D0SETSEL    (%u) in(%u)\n", IO_PRO.SEN.SENTOP.PHY0IFCTL.PHY0IFCTL1.bit.PHY0_D0SETSEL   , mode_ctrl[0].common_ctrl.d0setsel ));
        if(IO_PRO.SEN.SENTOP.PHY0IFCTL.PHY0IFCTL1.bit.PHY0_D1SETSEL != mode_ctrl[0].common_ctrl.d1setsel    ) Ddim_Print(( "Im_PRO_SENTOP_CPHY_Slvs_Mode_Ctrl() result:PHY0_D1SETSEL    (%u) in(%u)\n", IO_PRO.SEN.SENTOP.PHY0IFCTL.PHY0IFCTL1.bit.PHY0_D1SETSEL   , mode_ctrl[0].common_ctrl.d1setsel ));
