        if(IO_PRO.SEN.SENTOP.PHY1MDCTL.bit.PHY1_BITWIDTHSEL         != mode_ctrl[1].common_ctrl.bitwidthsel ) Ddim_Print(( "Im_PRO_SENTOP_CPHY_Slvs_Mode_Ctrl() result:PHY1_BITWIDTHSEL (%u) in(%u)\n", IO_PRO.SEN.SENTOP.PHY1MDCTL.bit.PHY1_BITWIDTHSEL           , mode_ctrl[1].common_ctrl.bitwidthsel  ));
