        if(IO_PRO.SEN.SENTOP.PHY1IFCTL.PHY1IFCTL1.bit.PHY1_D1SETSEL != mode_ctrl[1].common_ctrl.d1setsel    ) Ddim_Print(( "Im_PRO_SENTOP_CPHY_Slvs_Mode_Ctrl() result:PHY1_D1SETSEL    (%u) in(%u)\n", IO_PRO.SEN.SENTOP.PHY1IFCTL.PHY1IFCTL1.bit.PHY1_D1SETSEL   , mode_ctrl[1].common_ctrl.d1setsel ));
