        if(IO_PRO.SEN.SENTOP.PHY2IFCTL.PHY2IFCTL1.bit.PHY2_D1SETSEL != mode_ctrl[2].common_ctrl.d1setsel    ) Ddim_Print(( "Im_PRO_SENTOP_CPHY_Slvs_Mode_Ctrl() result:PHY2_D1SETSEL    (%u) in(%u)\n", IO_PRO.SEN.SENTOP.PHY2IFCTL.PHY2IFCTL1.bit.PHY2_D1SETSEL   , mode_ctrl[2].common_ctrl.d1setsel ));
        if(IO_PRO.SEN.SENTOP.PHY2IFCTL.PHY2IFCTL1.bit.PHY2_D2SETSEL != mode_ctrl[2].common_ctrl.d2setsel    ) Ddim_Print(( "Im_PRO_SENTOP_CPHY_Slvs_Mode_Ctrl() result:PHY2_D2SETSEL    (%u) in(%u)\n", IO_PRO.SEN.SENTOP.PHY2IFCTL.PHY2IFCTL1.bit.PHY2_D2SETSEL   , mode_ctrl[2].common_ctrl.d2setsel ));
        if(IO_PRO.SEN.SENTOP.PHY2IFCTL.PHY2IFCTL2.bit.PHY2_D3SETSEL != mode_ctrl[2].common_ctrl.d3setsel    ) Ddim_Print(( "Im_PRO_SENTOP_CPHY_Slvs_Mode_Ctrl() result:PHY2_D3SETSEL    (%u) in(%u)\n", IO_PRO.SEN.SENTOP.PHY2IFCTL.PHY2IFCTL2.bit.PHY2_D3SETSEL   , mode_ctrl[2].common_ctrl.d3setsel ));
