        if(IO_PRO.SEN.SENTOP.PHY3IFCTL.PHY3IFCTL1.bit.PHY3_D2SETSEL != mode_ctrl[3].common_ctrl.d2setsel    ) Ddim_Print(( "Im_PRO_SENTOP_CPHY_Slvs_Mode_Ctrl() result:PHY3_D2SETSEL    (%u) in(%u)\n", IO_PRO.SEN.SENTOP.PHY3IFCTL.PHY3IFCTL1.bit.PHY3_D2SETSEL   , mode_ctrl[3].common_ctrl.d2setsel ));
        if(IO_PRO.SEN.SENTOP.PHY3IFCTL.PHY3IFCTL2.bit.PHY3_D3SETSEL != mode_ctrl[3].common_ctrl.d3setsel    ) Ddim_Print(( "Im_PRO_SENTOP_CPHY_Slvs_Mode_Ctrl() result:PHY3_D3SETSEL    (%u) in(%u)\n", IO_PRO.SEN.SENTOP.PHY3IFCTL.PHY3IFCTL2.bit.PHY3_D3SETSEL   , mode_ctrl[3].common_ctrl.d3setsel ));
