        if(IO_PRO.SEN.SENTOP.PHY2MDCTL.bit.PHY2_PICNT               != mode_ctrl[2].picnt                   ) Ddim_Print(( "Im_PRO_SENTOP_CPHY_Slvs_Mode_Ctrl() result:PHY2_PICNT       (%u) in(%u)\n", IO_PRO.SEN.SENTOP.PHY2MDCTL.bit.PHY2_PICNT                 , mode_ctrl[2].picnt                    ));
